    private val psiquiatriaPack = LibraryContentPack(
        source = "[NÃO VERIFICADO] Rascunho gerado por IA — conferir contra: DSM-5-TR, Diretrizes APA, AMB, Canadian Network for Mood and Anxiety",
        items = listOf(
            LibraryContentItem(id = "psiq_001", title = "Depressão maior — critérios DSM-5", category = "CLINICA_MEDICA",
                summary = "Pelo menos 5 dos 9 sintomas (humor deprimido ou anedonia obrigatório) por ≥2 semanas.",
                content = "Transtorno Depressivo Maior (DSM-5-TR): ≥5 dos 9 sintomas presentes por ≥2 semanas consecutivas, representando mudança do funcionamento prévio. Sintomas: (1) humor deprimido na maior parte do dia, quase todos os dias; (2) anedonia (perda de interesse ou prazer); (3) perda/ganho de peso significativo (>5% em 1 mês) ou alteração de apetite; (4) insônia ou hipersonia; (5) agitação ou retardo psicomotor; (6) fadiga ou perda de energia; (7) sentimentos de inutilidade ou culpa excessiva; (8) diminuição da concentração ou indecisão; (9) pensamentos de morte, ideação suicida ou tentativa de suicídio. Pelo menos 1 deles deve ser (1) ou (2). Causa sofrimento clinicamente significativo ou prejuízo funcional. Excluir causas orgânicas (tireoide, B12, drogas).",
                tags = listOf("psiquiatria", "depressão", "dsm-5", "diagnóstico"), citation = "DSM-5-TR 2023 - Transtornos Depressivos"),
            LibraryContentItem(id = "psiq_002", title = "Escalas de depressão — PHQ-9, Hamilton, Beck", category = "CLINICA_MEDICA",
                summary = "PHQ-9 para rastreio (≥10 = alta probabilidade). Hamilton e Beck para gravidade e seguimento.",
                content = "Principais escalas de depressão: PHQ-9 (Patient Health Questionnaire-9): 9 perguntas autoaplicáveis, cada uma de 0-3. Escore ≥10: sensibilidade 88%, especificidade 88% para TDM. Intervalos: 0-4 mínima, 5-9 leve, 10-14 moderada, 15-19 moderada-grave, 20-27 grave. Item 9 (pensamentos suicidas) sempre avaliar. Escala de Hamilton (HAM-D): 17-21 itens, aplicada por clínico. Escores: 0-7 normal, 8-16 leve, 17-23 moderada, ≥24 grave. Mais usada em pesquisa. Escala de Beck (BDI-II): 21 itens autoaplicáveis, 0-63. 0-13 mínima, 14-19 leve, 20-28 moderada, 29-63 grave. Todas são úteis para rastreio e monitorização de resposta ao tratamento, mas não substituem entrevista clínica.",
                tags = listOf("psiquiatria", "depressão", "phq-9", "hamilton", "beck"), citation = "Diretriz APA 2023 - Depressão Maior"),
            LibraryContentItem(id = "psiq_003", title = "ISRS — fármacos e efeitos colaterais", category = "CLINICA_MEDICA",
                summary = "Sertralina, escitalopram, fluoxetina — efeitos: náusea, insônia, disfunção sexual, ativação inicial.",
                content = "ISRS (Inibidores Seletivos de Recaptação de Serotonina) — fármacos de 1ª linha na depressão: Sertralina 50-200 mg/dia (ansiolítico, seguro em idosos, poucas interações). Escitalopram 10-20 mg/dia (melhor tolerado, poucas interações). Fluoxetina 20-80 mg/dia (meia-vida longa, útil em baixa adesão, mas ativador). Paroxetina 20-50 mg/dia (mais ganho de peso, disfunção sexual, síndrome de retirada — evitar). Citalopram 20-40 mg/dia (risco de QT longo >40 mg). Efeitos colaterais comuns (2-4 semanas iniciais): náusea, cefaleia, diarreia, insônia/agitação (ativação precoce), sonolência. Disfunção sexual (30-60%): diminuição de libido, ejaculação retardada, anorgasmia. Síndrome de retirada (mais comum com paroxetina e venlafaxina). Síndrome serotoninérgica (rara, grave): hipertermia, rigidez, mioclonia, confusão.",
                tags = listOf("psiquiatria", "isrs", "sertralina", "escitalopram", "efeitos colaterais"), citation = "Diretriz APA 2023 - Depressão Maior"),
            LibraryContentItem(id = "psiq_004", title = "Inibidores de MAO — interação com tiramina", category = "CLINICA_MEDICA",
                summary = "Crise hipertensiva se ingerir tiramina (queijos, vinho tinto, embutidos, fermentados).",
                content = "Inibidores da Monoaminoxidase (IMAO): fenelzina, tranilcipromina, selegilina (transdérmica — menor risco). Mecanismo: inibem a degradação de monoaminas (serotonina, noradrenalina, dopamina). Interação crítica com tiramina: alimentos ricos em tiramina → crise hipertensiva (hipertensão severa, cefaleia intensa, HSA). Alimentos proibidos: queijos envelhecidos (parmesão, gorgonzola, cheddar), vinho tinto e cerveja, embutidos (salame, presunto cru, salsicha), chucrute, molho de soja, extrato de levedura, favas, figos enlatados, fígado de galinha. Também não pode usar com descongestionantes nasais, anfetaminas, levodopa. Dieta rigorosa é essencial durante todo o tratamento e 2 semanas após suspensão. Usar apenas quando 3-4 falhas de tratamento prévio (depressão refratária).",
                tags = listOf("psiquiatria", "imao", "tiramina", "crise hipertensiva", "interação"), citation = "Diretriz APA 2023 - Depressão Refratária"),
            LibraryContentItem(id = "psiq_005", title = "Transtorno de ansiedade generalizada — tratamento", category = "CLINICA_MEDICA",
                summary = "ISRS (escitalopram, sertralina) ou venlafaxina + TCC como primeira linha.",
                content = "Transtorno de Ansiedade Generalizada (TAG — DSM-5): preocupação excessiva ≥6 meses, associada a ≥3 de: inquietação, fadiga, dificuldade de concentração, irritabilidade, tensão muscular, sono perturbado. Tratamento: Farmacológico 1ª linha: ISRS (escitalopram 10-20 mg/dia, sertralina 50-200 mg/dia) ou venlafaxina 75-225 mg/dia (IRSN). Alternativas: duloxetina 60-120 mg/dia, pregabalina 150-600 mg/dia. Benzodiazepínicos: usar apenas no início (2-4 semanas) para ansiedade aguda, depois desmamar — risco de dependência. Duração: mínimo 6-12 meses após remissão. Psicoterapia: terapia cognitivo-comportamental (TCC) é tão eficaz quanto medicação. Combinação (fármaco + TCC) é superior a qualquer um isolado. Evitar cafeína, álcool, nicotina. Exercício aeróbico regular tem benefício comprovado.",
                tags = listOf("psiquiatria", "ansiedade", "tag", "isrs", "venlafaxina"), citation = "DSM-5-TR 2023 + Diretriz APA 2023 - TAG"),
            LibraryContentItem(id = "psiq_006", title = "Transtorno do pânico — tratamento", category = "CLINICA_MEDICA",
                summary = "Crise aguda: benzodiazepínico (clonazepam, alprazolam). Manutenção: ISRS ou venlafaxina.",
                content = "Transtorno do Pânico (DSM-5-TR): crises de ansiedade inesperadas recorrentes com ≥4 sintomas: palpitações, sudorese, tremor, dispneia, sensação de asfixia, dor torácica, náusea, tontura, calafrios/ondas de calor, parestesias, desrealização, medo de enlouquecer/morrer. Preocupação persistente sobre novas crises. Tratamento agudo: benzodiazepínico de alta potência — clonazepam 0,5 mg (2x/dia ou SOS) ou alprazolam 0,5-1 mg SOS. Manutenção: ISRS (escitalopram 10-20 mg/dia, sertralina 50-200 mg/dia) ou IRSN (venlafaxina 75-225 mg). Iniciar ISRS em doses baixas (metade da habitual) — pode piorar ansiedade no início. Associar BZD nas primeiras 2-4 semanas. TCC é altamente eficaz. Prognóstico: 70% boa resposta. Sem tratamento, curso crônico com agorafobia. Contraindicação: benzodiazepínicos em monoterapia além de 8 semanas.",
                tags = listOf("psiquiatria", "pânico", "clonazepam", "isrs"), citation = "Diretriz APA 2023 - Transtorno do Pânico"),
            LibraryContentItem(id = "psiq_007", title = "TOC — tratamento", category = "CLINICA_MEDICA",
                summary = "Clomipramina ou ISRS em altas doses + terapia de exposição e prevenção de resposta (TCC-EPR).",
                content = "Transtorno Obsessivo-Compulsivo (TOC — DSM-5-TR): obsessões (pensamentos intrusivos) e/ou compulsões (comportamentos repetitivos para reduzir ansiedade). Tratamento farmacológico 1ª linha: ISRS em doses altas (maiores que para depressão): fluoxetina 40-80 mg/dia, sertralina 150-250 mg/dia, escitalopram 20-30 mg/dia. Alternativa: clomipramina (antidepressivo tricíclico) 150-250 mg/dia — eficaz mas com mais efeitos colaterais (anticolinérgicos, ganho de peso, cardiotoxicidade). Efeito leva 8-12 semanas para aparecer. Tratamento psicológico: Terapia Cognitivo-Comportamental com Exposição e Prevenção de Resposta (TCC-EPR) — igualmente eficaz. Casos refratários: aumentar dose, adicionar aripiprazol, risperidona, ou lamotrigina. Estimulação cerebral profunda em casos graves e refratários. Duração: mínimo 1-2 anos após remissão.",
                tags = listOf("psiquiatria", "toc", "clomipramina", "isrs", "tcc"), citation = "Diretriz APA 2023 - TOC"),
            LibraryContentItem(id = "psiq_008", title = "Transtorno bipolar — critérios", category = "CLINICA_MEDICA",
                summary = "Episódios de mania (≥7 dias) e depressão. Tipo I: mania. Tipo II: hipomania + depressão maior.",
                content = "Transtorno Bipolar (DSM-5-TR): Tipo I: pelo menos 1 episódio de mania. Mania — humor elevado, expansivo ou irritável por ≥7 dias (ou menos se hospitalização), com ≥3 de: autoestima inflada, redução de sono, loquacidade, fuga de ideias, distração, agitação psicomotora, comportamento de risco (compras, sexo, investimentos). Prejuízo grave ou psicose. Tipo II: episódios de hipomania + depressão maior. Hipomania — mesmos sintomas por ≥4 dias, sem prejuízo grave. Ciclagem rápida: ≥4 episódios/ano. Especificadores: sazonal, pós-parto, congruente/incongruente com humor. Diagnóstico diferencial: transtorno de personalidade borderline (labilidade reativa a eventos), TDAH (crônico, sem episódios). Tratamento: estabilizadores de humor (lítio, valproato, lamotrigina, antipsicóticos atípicos). Antidepressivos podem induzir mania — usar com cautela e sempre associado a estabilizador.",
                tags = listOf("psiquiatria", "bipolar", "mania", "hipomania", "critérios"), citation = "DSM-5-TR 2023 - Transtorno Bipolar"),
            LibraryContentItem(id = "psiq_009", title = "Estabilizador de humor — lítio", category = "CLINICA_MEDICA",
                summary = "Dose alvo: nível sérico 0,6-1,2 mEq/L. Toxicidade >1,5 mEq/L (ataxia, confusão, coma).",
                content = "Lítio (carbonato de lítio): estabilizador de humor de primeira linha no transtorno bipolar. Dose: iniciar 300 mg 2-3x/dia. Ajustar conforme nível sérico (colher 12h após última dose). Níveis alvo: manutenção 0,6-1,0 mEq/L; mania aguda 0,8-1,2 mEq/L. Toxicidade: >1,5 mEq/L — sintomas leves (tremor, náusea, diarreia); >2,0 mEq/L — moderada (ataxia, disartria, letargia); >3,0 mEq/L — grave (convulsão, coma, PCR). Tratamento da intoxicação: suspender lítio, hidratação vigorosa, hemodiálise se grave. Efeitos colaterais: tremor (propranolol 10-20 mg 2x/dia), poliúria/polidipsia (diabetes insipidus nefrogênico), hipotireoidismo (TSH a cada 6 meses), ganho de peso, sedação leve. Contraindicações: IRC (clearance <30), disfunção tireoidiana descompensada. Monitorizar: litemia, TSH, função renal (Cr, uréia), ECG a cada 6 meses.",
                tags = listOf("psiquiatria", "lítio", "estabilizador", "toxicidade"), citation = "Diretriz APA 2023 - Transtorno Bipolar"),
            LibraryContentItem(id = "psiq_010", title = "Efeitos colaterais do lítio", category = "CLINICA_MEDICA",
                summary = "Tremor, polidipsia/poliúria, ganho de peso, hipotireoidismo, teratogênico (anomalia de Ebstein).",
                content = "Efeitos colaterais do lítio (muito comuns): Tremor fino — piora com café, ansiedade. Tratar com propranolol 10-40 mg/dia se incômodo. Poliúria/polidipsia — por diabetes insipidus nefrogênico (↓ expressão de aquaporina-2). Geralmente benigno, sem need de tratar se não houver hipernatremia. Ganho de peso — pode ser significativo. Hipotireoidismo — até 20-30% (↑ TSH). Tratar com levotiroxina. Teratogenicidade: anomalia de Ebstein (defeito da valva tricúspide) — risco 10x maior, mas ainda baixo (<1%). Evitar no 1º trimestre. Náusea/diarreia — melhorar tomando com alimentos (use forma de liberação lenta). Toxicidade renal crônica — fibrose intersticial, reduzir TFG a longo prazo. Monitorizar Cr e albuminúria anualmente. Risco de intoxicação: desidratação, AINEs, IECA, diuréticos tiazídicos — todos elevam litemia.",
                tags = listOf("psiquiatria", "lítio", "efeitos colaterais", "tremor", "tireoide"), citation = "Diretriz APA 2023 - Transtorno Bipolar"),
            LibraryContentItem(id = "psiq_011", title = "Antipsicóticos típicos (haloperidol)", category = "CLINICA_MEDICA",
                summary = "Efeitos extrapiramidais: distonia aguda, acatisia, pseudoparkinsonismo, discinesia tardia.",
                content = "Antipsicóticos típicos (1ª geração) — haloperidol, clorpromazina, flufenazina. Mecanismo: antagonistas D2 (dopamina). Efeitos adversos principais: extrapiramidais (EPMs): distonia aguda (espasmo muscular — pescoço, língua, olhos; tratar com biperideno 5 mg IM), acatisia (inquietação motora subjetiva e objetiva; tratar com propranolol 30-60 mg/dia ou benzodiazepínico), pseudoparkinsonismo (rigidez, bradicinesia, tremor; tratar com redução de dose ou anticolinérgico), discinesia tardia (movimentos involuntários orofaciais — geralmente irreversível, mais comum em idosos e tempo prolongado; prevenir com dose mínima eficaz). Hiperprolactinemia (galactorreia, ginecomastia, impotência). Sedação, hipotensão ortostática (clorpromazina). Síndrome neuroléptica maligna (SNM) — rara, grave (ver tópico específico). Usos: psicose aguda, agitação, mania, delirium (haloperidol IV/IM na UTI).",
                tags = listOf("psiquiatria", "antipsicótico", "haloperidol", "extrapiramidal", "discinesia tardia"), citation = "Diretriz APA 2023 - Esquizofrenia"),
            LibraryContentItem(id = "psiq_012", title = "Antipsicóticos atípicos", category = "CLINICA_MEDICA",
                summary = "Olanzapina, risperidona, quetiapina — ganho de peso, síndrome metabólica, menos EPMs.",
                content = "Antipsicóticos atípicos (2ª geração) — primeira linha para esquizofrenia e transtorno bipolar: Risperidona 2-8 mg/dia (menos ganho de peso, ↑ prolactina dose-dependente). Olanzapina 5-20 mg/dia (maior ganho de peso e dislipidemia, mas alta eficácia). Quetiapina 150-800 mg/dia (sedação, hipotensão, ganho de peso). Aripiprazol 10-30 mg/dia (agonista parcial D2 — menos ganho de peso, sem ↑ prolactina). Clozapina 100-900 mg/dia (reservada para refratários — risco de agranulocitose 1-2%, monitorizar leucograma semanal). Efeitos metabólicos: ganho de peso significativo (olanzapina > clozapina > quetiapina > risperidona > aripiprazol), hiperglicemia/DM, dislipidemia. Síndrome metabólica: monitorizar peso, glicemia, perfil lipídico a cada 3-6 meses. EPMs: menor incidência que típicos, mas podem ocorrer (risperidona em doses altas). Prolactina: risperidona ↑, aripiprazol não. Intervalo QT: risco com ziprasidona.",
                tags = listOf("psiquiatria", "antipsicótico atípico", "olanzapina", "risperidona", "síndrome metabólica"), citation = "Diretriz APA 2023 - Esquizofrenia"),
            LibraryContentItem(id = "psiq_013", title = "Síndrome neuroléptica maligna", category = "CLINICA_MEDICA",
                summary = "Febre, rigidez, rabdomiólise, disautonomia. Tratar: suspender antipsicótico, dantroleno, suporte.",
                content = "Síndrome Neuroléptica Maligna (SNM): emergência psiquiátrica rara (<1% dos usuários de antipsicóticos) mas grave (mortalidade 10-20%). Critérios: febre >38°C, rigidez muscular grave, alteração de consciência, disautonomia (taquicardia, instabilidade pressórica, arritmias), aumento de CPK (≥1.000 U/L — rabdomiólise), leucocitose. Fatores de risco: doses altas, ↑ rápida de dose, formulação IM de longa duração, desidratação, uso concomitante de lítio. Tratamento: suspender antipsicótico IMEDIATAMENTE. Suporte: hidratação vigorosa (rabdomiólise), resfriamento (hipertermia). Dantroleno 2-5 mg/kg/dia IV ou bromocriptina 2,5-15 mg 3x/dia via sonda. Se necessário: benzodiazepínicos para agitação. Internação em UTI. CPK retorna ao normal em 2-3 semanas. Não reiniciar antipsicótico por pelo menos 2 semanas; preferir atípico em dose baixa. A SNM não contraindica o uso futuro de antipsicóticos, mas exige cautela.",
                tags = listOf("psiquiatria", "neuroléptica maligna", "dantroleno", "urgência"), citation = "Diretriz APA 2023 - Esquizofrenia"),
            LibraryContentItem(id = "psiq_014", title = "Esquizofrenia — sintomas e tratamento", category = "CLINICA_MEDICA",
                summary = "Sintomas positivos (delírios, alucinações) e negativos (embotamento, avolição). Tto: antipsicóticos.",
                content = "Esquizofrenia (DSM-5-TR): ≥2 sintomas por ≥1 mês, com prejuízo social/ocupacional ≥6 meses. Sintomas positivos (respondem melhor a antipsicóticos): delírios (persecutórios mais comuns), alucinações (auditivas), desorganização de pensamento (discurso incoerente), comportamento desorganizado/catatônico. Sintomas negativos (menor resposta): embotamento afetivo, alogia (pobreza de fala), avolição (falta de iniciativa), anedonia social, déficits cognitivos (atenção, memória, função executiva). Tratamento: antipsicótico atípico como primeira linha (risperidona 2-8 mg/dia, olanzapina 10-20 mg/dia, quetiapina 300-800 mg/dia). Clozapina para refratários. Psicossocial: psicoeducação, reabilitação, terapia familiar, treino de habilidades sociais. Tratamento assistido se baixa adesão (antipsicótico IM de longa duração). Prognóstico: 20% bom (remissão completa), 50% curso flutuante, 30% curso crônico com declínio funcional.",
                tags = listOf("psiquiatria", "esquizofrenia", "antipsicótico", "positivo", "negativo"), citation = "DSM-5-TR 2023 - Esquizofrenia"),
            LibraryContentItem(id = "psiq_015", title = "Transtorno de personalidade borderline", category = "CLINICA_MEDICA",
                summary = "Instabilidade emocional, relacionamentos caóticos, medo de abandono, automutilação. Tto: DBT (psicoterapia).",
                content = "Transtorno de Personalidade Borderline (TPB — DSM-5-TR): padrão de instabilidade nas relações interpessoais, autoimagem e afetos. Critérios (≥5): medo de abandono, relacionamentos intensos/instáveis (idealização-desvalorização), perturbação de identidade, impulsividade (gastos, sexo, drogas, direção), comportamento suicida recorrente ou automutilação, instabilidade afetiva, sensação de vazio, raiva intensa/dificuldade de controle, ideação paranoide transitória (sob estresse). Tratamento: psicoterapia é a base — Terapia Comportamental Dialética (DBT — Marsha Linehan) é padrão ouro, reduz automutilação e ideação suicida. Outras: mentalização (MBT), TCC, esquema terapia. Farmacológico: sintomático — ISRS para depressão/labilidade, lamotrigina para instabilidade, antipsicóticos (aripiprazol, olanzapina) para cognição paranoide. Benzodiazepínicos devem ser evitados (desinibição, abuso). Curso crônico com melhora gradual com tratamento.",
                tags = listOf("psiquiatria", "borderline", "dbt", "automutilação"), citation = "DSM-5-TR 2023 - Transtornos de Personalidade"),
            LibraryContentItem(id = "psiq_016", title = "TDAH — tratamento", category = "CLINICA_MEDICA",
                summary = "Metilfenidato (Ritalina) 10-60 mg/dia ou lisdexanfetamina (Venvanse) 30-70 mg/dia. TCC complementar.",
                content = "Transtorno de Déficit de Atenção e Hiperatividade (TDAH — DSM-5-TR): início antes dos 12 anos, presente ≥2 ambientes, com ≥6 sintomas de desatenção e/ou hiperatividade-impulsividade. Adultos: ≥5 sintomas. Farmacoterapia de 1ª linha: psicoestimulantes — metilfenidato (Ritalina LA) 10-60 mg/dia (iniciar 10 mg, titular), lisdexanfetamina (Venvanse) 30-70 mg/dia (pró-fármaco, duração 10-14h). Efeitos colaterais: redução de apetite, insônia inicial, cefaleia, irritabilidade (on-rebound), discreto ↑PA/FC. Contraindicações: arritmia cardíaca, HAC não controlada, glaucoma, uso de IMAO. 2ª linha: atomoxetina (Strattera) 40-100 mg/dia — IRSN, não estimulante, sem potencial de abuso, mas efeito demora 4-8 semanas. TCC para adultos com TDAH complementa com organização, planejamento e gerenciamento de tempo. Conduta não-farmacológica: ajustes acadêmicos, organização, exercício, bom sono, redução de estímulos. Duração do tratamento: geralmente prolongado.",
                tags = listOf("psiquiatria", "tdah", "metilfenidato", "lisdexanfetamina"), citation = "Diretriz APA 2023 - TDAH em Adultos"),
            LibraryContentItem(id = "psiq_017", title = "Síndrome de abstinência alcoólica — tratamento", category = "CLINICA_MEDICA",
                summary = "Benzodiazepínicos (diazepam ou lorazepam) para controle de sintomas e prevenção de convulsão/delirium.",
                content = "Síndrome de abstinência alcoólica (SAA): sintomas 6-12h após última bebida: ansiedade, tremor, sudorese, náusea, irritabilidade, taquicardia, hipertensão. Complicações: convulsões (12-48h), delirium tremens (48-96h): alucinações visuais/táteis, agitação, confusão, febre, disautonomia grave. Tratamento de primeira linha: benzodiazepínicos — diazepam 10-20 mg VO/IV (meia-vida longa, menos flutuação) ou lorazepam 1-2 mg 6/6h (preferível em hepatopatas). Protocolo CIWA-Ar (Clinical Institute Withdrawal Assessment — Alcohol Revised): aplicar a cada 2-4h, tratar se ≥8-10. Esquema de carga: diazepam 20 mg a cada 1-2h até sedação leve. Hidratação, tiamina 300 mg/dia (prevenir síndrome de Wernicke-Korsakoff), correção de eletrólitos (K, Mg, P). Reposição de ácido fólico e vitaminas B-complex. Se delirium: haloperidol 5 mg IM + lorazepam 2 mg IM. Internação em UTI se febre, agitação grave, sinais vitais instáveis.",
                tags = listOf("psiquiatria", "abstinência", "álcool", "benzodiazepínico", "delirium tremens"), citation = "Diretriz APA 2023 - Transtornos por Uso de Substâncias"),
            LibraryContentItem(id = "psiq_018", title = "Escala CIWA-Ar para abstinência alcoólica", category = "CLINICA_MEDICA",
                summary = "10 itens que pontuam de 0-67. ≥8-10 indica tratamento com benzodiazepínico.",
                content = "CIWA-Ar (Clinical Institute Withdrawal Assessment for Alcohol — revised): 10 itens: náusea/vômito (0-7), tremor (0-7), sudorese paroxística (0-7), ansiedade (0-7), agitação (0-7), distúrbios táteis (0-6), auditivos (0-6), visuais (0-6), cefaleia/pressão na cabeça (0-7), orientação/sedação (0-7). Escore máximo: 67. Interpretação: <8 — leve (não tratar, observar). 8-15 — moderada (tratar com BZD e reavaliar). ≥15 — grave (BZD agressivo, monitorizar). ≥20 — risco de convulsão/delirium, admissão em UTI. Frequência de reaplicação: a cada 1-2h inicialmente, depois 4h quando estável (<8). Protocolo de sintoma-triggered: aplicar medicação apenas quando CIWA ≥8. É mais seguro e eficaz que esquema fixo. Útil para guiar tratamento e reduzir o uso excessivo de BZD.",
                tags = listOf("psiquiatria", "ciwa", "abstinência", "álcool", "escala"), citation = "Diretriz APA 2023 - Transtornos por Uso de Substâncias"),
            LibraryContentItem(id = "psiq_019", title = "Delirium — tratamento", category = "CLINICA_MEDICA",
                summary = "Tratar causa base. Haloperidol 0,5-5 mg IM/IV para agitação. Evitar BZD (exceto se abstinência alcoólica).",
                content = "Delirium (estado confusional agudo): início súbito (horas/dias), flutuação do nível de consciência, déficit de atenção, desorientação temporal, alteração do ciclo sono-vigília. Primeiro passo: identificar e tratar a causa base (infecção, distúrbio metabólico, droga, privação de sono, dor, imobilização). Farmacológico para agitação: haloperidol 0,5-5 mg IM/IV (iniciar com dose baixa em idosos: 0,5 mg). Repetir a cada 30 min se necessário. Dose máxima 20-30 mg/dia. ECG prévio para excluir QT longo. Alternativas: olanzapina 5-10 mg IM, risperidona 0,5-2 mg VO. Evitar benzodiazepínicos — podem piorar o delirium (exceto se abstinência alcoólica ou BZD). Não farmacológico: reorientação frequente, óculos/aparelho auditivo, mobilização precoce, ciclo claro/escuro, horário de visitas, redução de ruídos, evitar contenção desnecessária. Restabelecer medicações de uso crônico (parkinson, demência). Profilaxia (idosos cirúrgicos): dexmedetomidina reduz incidência.",
                tags = listOf("psiquiatria", "delirium", "haloperidol", "agitação"), citation = "Diretriz APA 2023 - Delirium"),
            LibraryContentItem(id = "psiq_020", title = "Ideação suicida — avaliação e manejo", category = "CLINICA_MEDICA",
                summary = "Avaliar: ideação, plano, acesso a meios, intenção. Risco iminente: hospitalização involuntária, supervisão 1:1.",
                content = "Avaliação de risco suicida (obrigatória em todo paciente deprimido ou com transtorno mental grave): Perguntar diretamente — não aumenta o risco. Investigar: ideação (pensamentos de morte, desejo de não acordar), plano (como, quando, onde), acesso a meios (arma, medicamentos, veneno), intenção (realmente pretende fazer), história de tentativas prévias (maior preditor), fatores de proteção (família, religião, projeto de vida). Fatores de risco: sexo masculino (completa mais), tentativa prévia, comorbidade psiquiátrica (depressão, bipolar, esquizofrenia, TPB, abuso substâncias), dor crônica, doenças terminais, isolamento social, perda recente, desemprego. Manejo: risco baixo → suporte ambulatorial, remover meios, rede de apoio. Risco moderado → contato frequente, contrato de segurança, envolver família. Risco alto (plano + intenção + meios) → hospitalização psiquiátrica involuntária, supervisão 1:1, ambiente seguro. Internação apenas com prescrição de contenção se necessário.",
                tags = listOf("psiquiatria", "suicídio", "avaliação", "risco", "hospitalização"), citation = "Diretriz APA 2023 - Avaliação de Risco Suicida"),
        )
    )

