    private val hematoOncoPack = LibraryContentPack(
        source = "[NÃO VERIFICADO] Rascunho gerado por IA — conferir contra: Diretrizes ASH, ESMO, INCA, NCCN — Hematologia e Oncologia",
        items = listOf(
            LibraryContentItem(id = "hemato_001", title = "Anemia ferropriva — diagnóstico", category = "CLINICA_MEDICA",
                summary = "VCM <80, ferritina <30, ferro sérico baixo, capacidade total de ferro elevada (TIBC >360).",
                content = "Anemia ferropriva (carência de ferro): Exames: hemograma — Hb baixa, VCM <80 (microcítica), HCM reduzida (hipocrômica), RDW aumentado (anisocitose). Perfil de ferro — ferro sérico baixo (<50 mcg/dL), ferritina baixa (<30 ng/mL é específico para deficiência de ferro; <100 ng/mL é sugestivo na presença de inflamação), capacidade total de ferro (TIBC) elevada (>360 mcg/dL), saturação de transferrina baixa (<20%). Causas: perda sanguínea crônica (menstruação, TGI — pólipo, CA cólon, úlcera, hemorroidas), má absorção (gastrite atrófica, doença celíaca, cirurgia bariátrica), aumento de demanda (gestação, lactação). Estadiamento: deficiência de ferro sem anemia (ferritina baixa, Hb normal) → anemia ferropriva leve → moderada → grave. Sempre investigar causa, especialmente perda oculta no TGI em homens e mulheres >45 anos.",
                tags = listOf("hematologia", "anemia ferropriva", "ferritina", "vcm"), citation = "Diretriz ASH 2023 - Anemia Ferropriva"),
            LibraryContentItem(id = "hemato_002", title = "Tratamento da anemia ferropriva", category = "CLINICA_MEDICA",
                summary = "Sulfato ferroso 60 mg 3x/dia (200 mg/dia de ferro elementar). Efeitos: constipação, fezes escuras.",
                content = "Tratamento da anemia ferropriva: Sulfato ferroso 60 mg (ferro elementar) 1-3x/dia (preferir 3x/dia em jejum para melhor absorção). Dose total de ferro elementar: 100-200 mg/dia para adultos. Duração: tratar até normalizar Hb (4-8 semanas), depois continuar por mais 3-6 meses para repor estoques (ferritina >50 ng/mL). Efeitos colaterais: náusea, epigastralgia, constipação, fezes escuras (orientar!). Tomar com suco de lúcia-limão/ácido ascórbico (↑ absorção). Evitar com café, chá, leite, antiácidos (↓ absorção). Se intolerância oral: ferro líquido, mudar para sal diferente (gliconato ferroso), ou reduzir frequência. Alternativas: ferro endovenoso (ferro-sacarose 200 mg IV, ferricarboximaltose 1.000 mg IV) em casos de intolerância grave, má absorção, IRC, ou necessidade de reposição rápida. Risco de anafilaxia com ferro IV (observar 30 min após infusão). Investigar e tratar causa base.",
                tags = listOf("hematologia", "sulfato ferroso", "anemia", "ferro"), citation = "Diretriz ASH 2023 - Anemia Ferropriva"),
            LibraryContentItem(id = "hemato_003", title = "Anemia megaloblástica — diagnóstico", category = "CLINICA_MEDICA",
                summary = "VCM >100 (macrocítica). Deficiência de B12 e/ou ácido fólico. Esfregaço: neutrófilos hipersegmentados.",
                content = "Anemia megaloblástica (deficiência de B12/folato): Hemograma: Hb baixa, VCM >100 (macrocítica), CHCM normal (normocrômica). Esfregaço de sangue periférico: neutrófilos hipersegmentados (>5 lóbulos, ou presença de neutrófilos com ≥6 lóbulos), ovalócitos, corpúsculos de Howell-Jolly, pontilhado basofílico. Exames: B12 sérico baixo (<200 pg/mL), folato sérico baixo (<4 ng/mL) ou folato eritrocitário baixo (<150 ng/mL) — mais confiável. Ácido metilmalônico (MMA) e homocisteína — elevados na deficiência de B12; homocisteína elevada e MMA normal na deficiência de folato. Causas de deficiência de B12: anemia perniciosa (anticorpo anti-fator intrínseco e anticorpo anti-célula parietal), má absorção (gastrite atrófica, cirurgia gástrica, Crohn, bactérias), veganos/vegetarianos estritos, idade avançada. Causas de deficiência de folato: dieta pobre, alcoolismo, gestação, hemólise crônica, drogas (metotrexato, fenitoína, sulfassalazina).",
                tags = listOf("hematologia", "anemia megaloblástica", "b12", "folato", "macrocítica"), citation = "Diretriz ASH 2023 - Anemia Megaloblástica"),
            LibraryContentItem(id = "hemato_004", title = "Causa mais comum de deficiência de B12", category = "CLINICA_MEDICA",
                summary = "Anemia perniciosa — deficiência de fator intrínseco autoimune (anticorpo anti-fator intrínseco).",
                content = "Anemia perniciosa: causa mais comum de deficiência de B12 em adultos (ocorre em 2% da população >60 anos). Fisiopatologia: gastrite atrófica autoimune do corpo gástrico → destruição de células parietais → ↓ fator intrínseco → ↓ absorção de B12 no íleo terminal. Anticorpos: anti-célula parietal (+ em 85%), anti-fator intrínseco (+ em 50-70%). Associação com outras doenças autoimunes (tireoidite de Hashimoto, DM tipo 1, vitiligo). Quadro clínico: anemia megaloblástica, glossite (língua lisa e vermelha), sintomas neurológicos — parestesias, déficit de vibração/propriocepção (desmielinização do funículo posterior da medula), ataxia, sinal de Lhermitte (choque ao fletir pescoço). Diagnóstico: B12 baixa + anticorpo anti-fator intrínseco + gastrite atrófica na endoscopia. Tratamento: B12 IM 1.000 mcg/dia por 1 sem, depois semanal por 1 mês, depois mensal para toda a vida. Risco de hipocalemia (rebound) com início do tratamento.",
                tags = listOf("hematologia", "anemia perniciosa", "b12", "autoimune", "fator intrínseco"), citation = "Diretriz ASH 2023 - Deficiência de B12"),
            LibraryContentItem(id = "hemato_005", title = "Tratamento da deficiência de B12", category = "CLINICA_MEDICA",
                summary = "Cianocobalamina 1.000 mcg IM 1x/semana por 1 mês, depois 1x/mês vitalício. VO é alternativa apenas para causas dietéticas.",
                content = "Tratamento da deficiência de B12: Cianocobalamina (B12) 1.000 mcg IM ou SC. Esquema para anemia perniciosa/má absorção: ataque — 1.000 mcg/dia por 1 semana, depois 1.000 mcg/semana por 4 semanas (8 doses). Manutenção: 1.000 mcg/mês para toda a vida. Alternativa oral (apenas para deficiência dietética): 1.000-2.000 mcg/dia VO — a absorção passiva independe de fator intrínseco e cobre 1% da dose (10-20 mcg). Para veganos sem má absorção: suplementação oral de 50-100 mcg/dia é suficiente. Resposta: reticulocitose em 7-10 dias, correção de Hb em 4-8 semanas. Monitorizar sintomas neurológicos — podem levar meses para melhorar. Risco de hipocalemia com o início do tratamento (consumo de K+ pela eritropoese aumentada). Nunca tratar suspeita de deficiência de B12 com ácido fólico isolado — pode corrigir anemia mas piorar déficit neurológico (piora irreversível).",
                tags = listOf("hematologia", "b12", "cianocobalamina", "reposição"), citation = "Diretriz ASH 2023 - Deficiência de B12"),
            LibraryContentItem(id = "hemato_006", title = "Anemia hemolítica — teste de Coombs", category = "CLINICA_MEDICA",
                summary = "Coombs direto (DAT): positivo em anemia hemolítica autoimune. Coombs indireto: positivo em aloimunização.",
                content = "Teste de Coombs (teste de antiglobulina direta e indireta): Coombs Direto (DAT — Direct Antiglobulin Test): detecta anticorpos ou complemento ligados à superfície das hemácias. POSITIVO em: anemia hemolítica autoimune (AHAI), doença hemolítica do RN, reação transfusional hemolítica, drogas (metildopa, penicilina, quinidina). Coombs Indireto (IAT): detecta anticorpos livres no soro (não ligados às hemácias). POSITIVO em: aloimunização (transfusão prévia, gestação), doença hemolítica do RN (triagem pré-natal). Anemia hemolítica: achados — ↑ LDH (marcador mais sensível), ↓ haptoglobina (consome com hemólise), ↑ bilirrubina indireta, ↑ reticulócitos, esfregaço com esferócitos ou esquizócitos (CIVD, PTT). Coombs negativo: se forte suspeita de AHAI, repetir — pode ter baixa densidade de IgG. Diagnóstico diferencial: hemoglobinúria paroxística noturna (HPN — CD55/CD59 negativo), deficiência de G6PD, esferocitose hereditária.",
                tags = listOf("hematologia", "coombs", "hemólise", "aai", "diagnóstico"), citation = "Diretriz ASH 2023 - Anemia Hemolítica"),
            LibraryContentItem(id = "hemato_007", title = "Esferocitose hereditária", category = "CLINICA_MEDICA",
                summary = "Esfregaço com esferócitos, teste de fragilidade osmótica aumentado. Esplenectomia é curativa.",
                content = "Esferocitose hereditária: doença hereditária mais comum da membrana eritrocitária (herança autossômica dominante na maioria). Defeito: deficiência de espectrina, anquirina ou banda 3 → perda de superfície da membrana → esferócitos. Quadro clínico: anemia hemolítica de gravidade variável, icterícia, esplenomegalia, crise aplástica (parvovírus B19 — ↓ reticulócitos súbito), litíase biliar (hiperbilirrubinemia indireta crônica → cálculos pigmentares). Diagnóstico: esfregaço com esferócitos (hemácias densas, sem palidez central), ↑ LDH, ↓ haptoglobina, reticulocitose, bilirrubina indireta elevada. Teste de fragilidade osmótica aumentada — hemácias lisam em soluções salinas mais concentradas que o normal. Teste de eosina-5-maleimida (EMA) — citometria de fluxo confirma. Tratamento: ácido fólico 5 mg/dia suplementar. Esplenectomia → curativa (↓ hemólise, melhora Hb). Indicada se anemia grave (Hb <8) ou sintomática (cálculos, crises). Vacinar contra: pneumococo, meningococo, H. influenzae (2-4 semanas antes da esplenectomia). Profilaxia antibiótica pós-esplenectomia (penicilina V 250 mg 2x/dia ou fenoximetilpenicilina).",
                tags = listOf("hematologia", "esferocitose", "esferócitos", "esplenectomia"), citation = "Diretriz ASH 2023 - Anemias Hereditárias"),
            LibraryContentItem(id = "hemato_008", title = "Talassemia — diagnóstico", category = "CLINICA_MEDICA",
                summary = "Eletroforese de hemoglobina: HbA2 >3,5% na beta-talassemia minor. HbH ou Hb Bart's na alfa-talassemia.",
                content = "Talassemia: deficiência na síntese de globina. Beta-talassemia: mais comum no Brasil. Beta minor (traço): mutação heterozigótica — hemograma com Hb discretamente baixa, VCM muito baixo (<75), morfologia com microcitose e hipocromia. Eletroforese de Hb: HbA2 elevada (>3,5%) é diagnóstico (HbA até 95%, HbA2 3,5-7%, HbF normal ou discretamente ↑). Diagnóstico diferencial de anemia microcítica: ferritina normal (vs ferropriva). Beta major (talassemia homozigótica, anemia de Cooley): anemia grave, icterícia, deformidades ósseas (face em ouriço), hepatomegalia, retardo de crescimento. Dependente de transfusões. Alfa-talassemia: diagnóstico por eletroforese + DNA (HbH = β4, Hb Bart's = γ4). Tratamento: minor — suplementar ácido fólico, evitar ferro (pode haver sobrecarga de ferro). Major — transfusões regulares + quelante de ferro (deferoxamina, deferasirox). Transplante de medula óssea é curativo. Aconselhamento genético em casais de risco.",
                tags = listOf("hematologia", "talassemia", "hemoglobina", "eletroforese"), citation = "Diretriz ASH 2023 - Talassemia"),
            LibraryContentItem(id = "hemato_009", title = "Anemia falciforme — diagnóstico e tratamento", category = "CLINICA_MEDICA",
                summary = "Diagnóstico: eletroforese HbS. Tratamento: hidroxiureia, transfusões, ácido fólico, vacinação, prevenção de crises.",
                content = "Doença falciforme (HbSS — homozigose): Hemoglobina S → polimerização → hemácias em foice → vaso-oclusão. Diagnóstico: eletroforese de hemoglobina mostra HbS >80% (HbA ausente, HbF 2-10%). Teste do pezinho detecta ao nascimento. Tratamento: Hidroxiureia 15-35 mg/kg/dia (aumenta HbF, reduz crises vaso-oclusivas em 50%). Ácido fólico 5 mg/dia suplementar. Transfusões: indicações — crise aguda grave, AVC, síndrome torácica aguda, preparo cirúrgico. Transfusão simples ou eritrocitoférese (troca). Vacinação: pneumococo, meningococo, H. influenzae, hepatite B, influenza anualmente. Penicilina profilática: <5 anos — 125 mg 2x/dia; ≥5 anos — 250 mg 2x/dia (até 5 anos). Prevenção de crises: hidratação abundante, evitar frio, evitar altitude >2.000m, evitar desidratação. Tratamento de crises: hidratação, analgesia (AINES, opioides), oxigênio se hipóxia, suporte. Complicações: AVC (5-10% das crianças — precisa de transfusão crônica), síndrome torácica aguda (causa mais comum de morte), sequestro esplênico, priapismo, úlceras de perna. Transplante de medula é curativo. Terapia gênica emergente.",
                tags = listOf("hematologia", "anemia falciforme", "hidroxiureia", "eletroforese"), citation = "Diretriz MS Brasil 2023 - Doença Falciforme"),
            LibraryContentItem(id = "hemato_010", title = "Púrpura trombocitopênica idiopática (PTI)", category = "CLINICA_MEDICA",
                summary = "Plaquetas <100.000, sem outras citopenias. Tratamento: corticoide (prednisona 1 mg/kg) ± imunoglobulina.",
                content = "Púrpura Trombocitopênica Imunomediada (PTI): plaquetopenia isolada (plaquetas <100.000/mm³) por destruição autoimune (anticorpos anti-GPIb/IIb/IIIa). Primária (idiopática) ou secundária (Lupus, HIV, HCV, H. pylori, linfoma, drogas). Quadro: petéquias, equimoses, sangramento mucocutâneo (gengiva, epistaxe, menorragia). Raramente sangramento grave (SNC, TGI) se plaquetas >10.000. Diagnóstico de exclusão: hemograma com plaquetopenia isolada (Hb, leucócitos normais). Medula óssea (raramente necessária): megacariócitos normais/aumentados. Teste de anticorpos antiplaquetas (baixa sensibilidade). Tratamento: prednisona 1 mg/kg/dia VO por 2-4 semanas, depois desmame. Resposta em 2-4 sem (70%). Se sangramento ativo ou preparo cirúrgico: imunoglobulina EV (IGIV) 1 g/kg 1-2 doses. Se refratário: rituximabe (anti-CD20), eltrombopag ou romiplostim (agonistas de trombopoetina), esplenectomia (reservada para refratários — curativa em 60-70%). Crianças: geralmente autolimitada, tratar só se sangramento ativo.",
                tags = listOf("hematologia", "pti", "plaquetopenia", "prednisona", "imunoglobulina"), citation = "Diretriz ASH 2023 - Púrpura Trombocitopênica Imunomediada"),
            LibraryContentItem(id = "hemato_011", title = "Púrpura trombocitopênica trombótica (PTT)", category = "CLINICA_MEDICA",
                summary = "Pentágono: anemia hemolítica microangiopática + plaquetopenia + IRA + febre + alteração neurológica.",
                content = "Púrpura Trombocitopênica Trombótica (PTT/Síndrome de Moschcowitz): Deficiência de ADAMTS13 (↓ capacidade de clivar multímeros de vWF) → microtrombos plaquetários disseminados. Pentágono clínico (presente apenas em 40%): anemia hemolítica microangiopática (esquizócitos no esfregaço), plaquetopenia grave (<30.000), disfunção renal (IRA), febre, alterações neurológicas (cefaleia, confusão, AVC, convulsão). Laboratório: ↑ LDH, ↓ haptoglobina, Coombs negativo, ↑ bilirrubina indireta, plaquetopenia, creatinina elevada, ADAMTS13 <10% (confirma). Tratamento de emergência: plasmaférese diária (troca de 1-1,5 volumes plasmáticos) — padrão ouro, reduz mortalidade de >90% para 10-20%. Prednisona 1 mg/kg/dia adjuvante. Caplacizumabe (inibidor de vWF) — casos refratários. Rituximabe se refratário ou recidiva. Transfusão de plaquetas é contraindicada (exceto sangramento grave com risco de morte) — pode piorar microtrombos. Diagnóstico diferencial: CIVD (TP/TTPa alargados, fibrinogênio baixo), síndrome hemolítico-urêmica (SHU — diarreia, E. coli O157:H7, mais disfunção renal). Tratamento de suporte na SHU (hidratação) — plasmaférese não indicada.",
                tags = listOf("hematologia", "ptt", "plaquetopenia", "plasmaférese", "esquizócitos"), citation = "Diretriz ASH 2023 - Púrpura Trombocitopênica Trombótica"),
            LibraryContentItem(id = "hemato_012", title = "Hemofilia A — fator VIII", category = "CLINICA_MEDICA",
                summary = "Deficiência de fator VIII (hemofilia A). Tratamento: concentrado de fator VIII. Dose = peso x %desejado x 0,5.",
                content = "Hemofilia A (deficiência de fator VIII, ligada ao X — 1:5.000 homens): Gravidade: grave (<1% de fator VIII) — hemartroses espontâneas, hematomas, sangramento intracraniano; moderada (1-5%) — sangramento após trauma leve; leve (5-40%) — sangramento após trauma/cirurgia. Tratamento: concentrado de fator VIII recombinante (ou plasmático). Cálculo da dose: 1 UI/kg aumenta fator VIII em 2%. Dose = peso (kg) × (% desejado - % basal) × 0,5 (para FVIII). Exemplo: paciente de 70kg com hemartrose (alvo 50%): 70 × 50 × 0,5 = 1.750 UI. Hemartrose: alvo 30-50% por 1-3 dias. Cirurgia: alvo 80-100% no pré-op, manter >50% por 5-7 dias. Profilaxia primária: iniciar <2 anos, infusão 2-3x/semana para prevenir artropatia hemofílica. Inibidores: 30% desenvolvem anticorpo anti-FVIII → necessitam de bypass (FEIBA, fator VII ativado recombinante). Desmopressina (DDAVP) — funciona apenas em hemofilia A leve (aumenta FVIII e vWF 2-4x). Tratamento da artropatia: fisioterapia, evitar AINEs. Orientar: evitar AAS, prática de esportes de contato. Aconselhamento genético. Crioprecipitado — alternativa quando concentrado indisponível.",
                tags = listOf("hematologia", "hemofilia a", "fator viii", "coagulopatia"), citation = "Diretriz ASH 2023 - Hemofilia"),
            LibraryContentItem(id = "hemato_013", title = "Hemofilia B — fator IX", category = "CLINICA_MEDICA",
                summary = "Deficiência de fator IX (hemofilia B). Tratamento: concentrado de fator IX. Dose = peso x %desejado x 1,0.",
                content = "Hemofilia B (deficiência de fator IX, ligada ao X — 1:25.000 homens): Clínica idêntica à hemofilia A (hemartroses, hematomas, sangramentos). Diagnóstico: dosagem de fator IX baixa, TP normal, TTPa alargado. Tratamento: concentrado de fator IX recombinante ou plasmático. Cálculo: 1 UI/kg de FIX aumenta 1% — dose = peso (kg) × (% desejado - % basal) × 1,0 (diferente do FVIII que é × 0,5 — porque o FIX tem maior volume de distribuição). Exemplo: paciente 70kg com sangramento grave (alvo 80%): 70 × 80 × 1,0 = 5.600 UI. Meia-vida do FIX: 18-24h (mais longa que FVIII). Profilaxia: 2-3x/semana. Inibidores menos comuns que na hemofilia A (3-5%). Desmopressina NÃO funciona (FIX não é armazenado em endotélio). Plasma fresco congelado — alternativa se concentrado indisponível (contém todos os fatores). Gene therapy (etranacogene dezaparparvovec) — aprovado para hemofilia B (aumenta FIX expressão, reduz taxas de infusão). Artropatia hemofílica: resultado de sangramentos articulares repetidos → sinovite → erosão da cartilagem. Profilaxia primária (desde <2 anos) previne.",
                tags = listOf("hematologia", "hemofilia b", "fator ix", "coagulopatia"), citation = "Diretriz ASH 2023 - Hemofilia"),
            LibraryContentItem(id = "hemato_014", title = "Doença de von Willebrand — tratamento", category = "CLINICA_MEDICA",
                summary = "Desmopressina (DDAVP) se tipo 1. Tipo 3 e 2: concentrado de vWF (fator VIII + vWF).",
                content = "Doença de von Willebrand (DvW — deficiência/defeito do fator de von Willebrand): Tipo 1 (70-80%): deficiência quantitativa parcial — mais comum, autossômica dominante. Tipo 2 (20%): defeito qualitativo (2A, 2B, 2M, 2N). Tipo 3 (<5%): deficiência completa — grave, recessiva. Quadro: epistaxe, menorragia, hematomas fáceis, sangramento prolongado após extração dentária/cirurgia. Diagnóstico: antígeno vWF (vWF:Ag) baixo, atividade de vWF (ristocetina cofator) baixa, fator VIII baixo (vWF carreia FVIII), tempo de sangramento (TS) alargado (ou PFA-100 >150-180s). Tratamento: Tipo 1 — desmopressina (DDAVP) 0,3 mcg/kg IV/SC (libera vWF dos estoques endoteliais). Aumenta vWF e FVIII 2-5x em 30 min. Duração 6-12h. Teste de resposta antes do uso. Tipo 2 e 3: concentrado de fator VIII + vWF (Humate-P, Wilate). Crioprecipitado (risco viral, evitar se possível). Não usar DDAVP no tipo 2B (piora trombocitopenia). Menorragia: ácido tranexâmico (1g 6/6h) ou ACO. Evitar AAS, AINEs. Tratamento odontológico: ácido tranexâmico bochecho + DDAVP se necessário.",
                tags = listOf("hematologia", "von willebrand", "desmopressina", "coagulopatia"), citation = "Diretriz ASH 2023 - Doença de von Willebrand"),
            LibraryContentItem(id = "hemato_015", title = "Leucemia linfoide aguda (LLA) — tratamento", category = "CLINICA_MEDICA",
                summary = "Quimioterapia intensiva (protocolo hiper-CVAD ou BFM). Prognóstico favorável em crianças (80% de cura).",
                content = "Leucemia Linfoide Aguda (LLA): proliferação clonal de linfoblastos na medula óssea. Mais comum em crianças (pico 2-5 anos). Quadro: fadiga, palidez, febre, infecções, petéquias/equimoses, dor óssea, hepatoesplenomegalia, linfadenomegalia. Hemograma: leucocitose com blastos, anemia, plaquetopenia. Diagnóstico: mielograma >20% blastos linfoides (L1, L2, L3). Imunofenotipagem (B, T). Classificação: B-ALL (75%), T-ALL (25%). Risco: idade (<1 ou >60 risco maior), leucócitos >50.000 (B) ou >100.000 (T), citogenética (t[9;22] — Filadélfia — pior, t[12;21] — melhor). Tratamento: quimioterapia por 2-3 anos: indução (vincristina, corticoide, daunorrubicina, L-asparaginase) → consolidação → manutenção (metotrexato + 6-mercaptopurina). Profilaxia SNC (metotrexato IT). Transplante de medula: refratários ou Ph+. Prognóstico: crianças 80-90% cura; adultos 30-50% (idosos pior). Efeitos colaterais: mielossupressão, cardiotoxicidade (antraciclinas — dose cumulativa máxima), osteonecrose (corticoide). Síndrome de lise tumoral — profilaxia: alopurinol, hidratação, rasburicase.",
                tags = listOf("oncologia", "leucemia linfoide aguda", "quimioterapia", "hiper-cvad"), citation = "Diretriz NCCN 2023 - LLA"),
            LibraryContentItem(id = "hemato_016", title = "Leucemia mieloide aguda (LMA) — tratamento", category = "CLINICA_MEDICA",
                summary = "Classificação FAB (M0 a M7). Tratamento: indução 7+3 (citarabina + daunorrubicina).",
                content = "Leucemia Mieloide Aguda (LMA): proliferação clonal de mieloblastos. Mais comum em idosos (mediana 67 anos). Quadro: fadiga, palidez, febre, infecções, coagulopatia (M3 promielocítica), equimoses, petéquias. Diagnóstico: blastos >20% na medula. Citogenética determina prognóstico (bom: inv[16], t[8;21]; ruim: monossomia 5/7, t[9;22], complexo). Classificação FAB (M0 a M7): M0 — minimamente diferenciada, M1 — sem maturação, M2 — com maturação, M3 — promielocítica, M4 — mielomonocítica, M5 — monocítica, M6 — eritroleucemia, M7 — megacarioblástica. Tratamento padronizado: Indução 7+3: citarabina 100-200 mg/m²/dia por 7 dias + daunorrubicina 60 mg/m²/dia por 3 dias. Resposta em 2-4 semanas (60-80% remissão). Se refratário: FLAG-IDA (fludarabina, Ara-C, G-CSF, idarrubicina), cladribina, CPX-351 (Vyxos) para LMA secundária. LMA M3 (promielocítica): ácido all-trans retinóico (ATRA) + trióxido de arsênico (ATO) — sem quimioterapia convencional (cura >90%). Consolidação: citarabina em altas doses 3-4 ciclos. Transplante de medula: prognóstico adverso/intermediário. Suporte transfusional, profilaxia de lise tumoral.",
                tags = listOf("oncologia", "lma", "leucemia mieloide", "7+3", "citarabina"), citation = "Diretriz NCCN 2023 - LMA"),
            LibraryContentItem(id = "hemato_017", title = "Síndrome mielodisplásica — tratamento", category = "CLINICA_MEDICA",
                summary = "Agentes hipometilantes (azacitidina, decitabina) como primeira linha. Transplante de medula é curativo.",
                content = "Síndrome Mielodisplásica (SMD): doença clonal da célula-tronco hematopoética, caracterizada por hematopoese ineficaz e risco de transformação para LMA. Quadro: anemia (mais comum), plaquetopenia, neutropenia. Classificação IPSS-R (Revised International Prognostic Scoring System): baseada em % blastos medulares, citogenética, Hb, plaquetas, neutrófilos → determina risco (muito baixo, baixo, intermediário, alto, muito alto) e sobrevida. Risco baixo (idade >60 anos, sem deleção 5q isolada): tratar sintomas — transfusões, eritropoetina (se EPO <500), quelante de ferro (se >20 transfusões). Deleção 5q isolada: lenalidomida (resposta 60%). Risco alto: agentes hipometilantes — azacitidina 75 mg/m² SC por 7 dias a cada 28 dias. Alternativa: decitabina 20 mg/m² IV por 5 dias a cada 28 dias. Azacitidina melhora sobrevida (24 vs 15 meses) comparado a cuidado de suporte. Transplante de medula alogênico: única opção curativa (pacientes jovens, <65 anos, doador disponível). LMA pós-SMD: tratar como SMD de alto risco (quimioterapia intensiva geralmente não funciona).",
                tags = listOf("oncologia", "síndrome mielodisplásica", "azacitidina", "ipss-r"), citation = "Diretriz NCCN 2023 - SMD"),
            LibraryContentItem(id = "hemato_018", title = "Mieloma múltiplo — critérios CRAB", category = "CLINICA_MEDICA",
                summary = "CRAB: Cálcio elevado, Renal (insuficiência), Anemia, Bone (lesões ósseas líticas). Tratamento com bortezomibe + lenalidomida + dexametasona.",
                content = "Mieloma Múltiplo: neoplasia de plasmócitos com produção de imunoglobulina monoclonal (pico monoclonal). Quadro clínico — CRAB: C (hipercalcemia) — cálcio >11 mg/dL, R (insuficiência renal) — Cr >2 ou clearance <40, A (anemia) — Hb <10 g/dL ou >2g abaixo do normal, B (bone lesions) — lesões líticas na radiografia ou RNM. Outros: infecções recorrentes, hiperviscosidade, neuropatia periférica (amiloidose). Diagnóstico: eletroforese de proteínas séricas com pico monoclonal, imunofixação, cadeias leves livres no soro, biópsia de medula >10% plasmócitos clonais. Tratamento: Indução (candidatos a transplante): bortezomibe + lenalidomida + dexametasona (VRd). Alternativa: daratumumabe + lenalidomida + dexametasona (DRd). Indução com 3-4 ciclos, seguido de mobilização e transplante autólogo de medula (condicionamento com melfalano 200 mg/m²). Manutenção pós-transplante: lenalidomida até progressão. Não candidatos a transplante: lenalidomida + dexametasona (Rd) ou daratumumabe + lenalidomida + dexametasona (DRd). Tratamento de suporte: bisfosfonatos (ácido zoledrônico 4 mg IV/mês ou pamidronato 90 mg IV/mês) para lesões ósseas, controle da dor, hidratação para IRA, vacinação (pneumococo, influenza), profilaxia de herpes zoster.",
                tags = listOf("oncologia", "mieloma", "crab", "bortezomibe", "lenalidomida"), citation = "Diretriz NCCN 2023 - Mieloma Múltiplo"),
            LibraryContentItem(id = "hemato_019", title = "Linfoma de Hodgkin — tratamento", category = "CLINICA_MEDICA",
                summary = "Células de Reed-Sternberg. Tratamento: ABVD (doxorrubicina, bleomicina, vinblastina, dacarbazina).",
                content = "Linfoma de Hodgkin (LH): neoplasia linfóide com células de Reed-Sternberg (grandes, bilobadas, nucléolo proeminente). Bimodal: 15-35 anos e >55 anos. Quadro: linfadenomegalia cervical/supraclavicular indolor (70%), febre, sudorese noturna, perda de peso (sintomas B — 30%), prurido, dor linfonodal ao álcool. Diagnóstico: biópsia excisional de linfonodo (agulha fina não serve). Imuno-histoquímica: CD15+, CD30+, CD45-, CD20-/+. Estadiamento Ann Arbor: I — 1 cadeia; II — ≥2 cadeias mesmo lado do diafragma; III — ambos lados; IV — disseminação extranodal. A ou B (sintomas). Tratamento: estádio inicial (I-II A favorável): ABVD 2-4 ciclos + radioterapia envolvida (20 Gy). Estádio avançado (III-IV ou II B): ABVD 6 ciclos. ABVD — doxorrubicina (Adriamycin) 25 mg/m², bleomicina 10 mg/m², vinblastina 6 mg/m², dacarbazina 375 mg/m² D1 e D15 a cada 28 dias. Resposta avaliada com PET-CT após 2 ciclos (PET-2). Se PET-2 positivo (Deauville 4-5): trocar para esquema de resgate. Alternativa: BEACOPP (Bleomicina, Etoposídeo, Adriamicina, Ciclofosfamida, Oncovin, Procarbazina, Prednisolona) — Europa. Efeitos colaterais: cardiotoxicidade (doxorrubicina), pneumotoxicidade (bleomicina), infertilidade, MDS/leucemia secundária (raro). Prognóstico: excelente — cura 80-90%.",
                tags = listOf("oncologia", "hodgkin", "reed- Sternberg", "abvd"), citation = "Diretriz NCCN 2023 - Linfoma de Hodgkin"),
            LibraryContentItem(id = "hemato_020", title = "Linfoma não Hodgkin — tratamento", category = "CLINICA_MEDICA",
                summary = "Classificação WHO. Tratamento: CHOP (ciclofosfamida, doxorrubicina, vincristina, prednisona) + rituximabe (R-CHOP).",
                content = "Linfoma Não Hodgkin (LNH): grupo heterogêneo de neoplasias linfóides. Mais comum que LH, mais comum em idosos. Tipos principais: Linfoma difuso de grandes células B (LDGCB — 30%) — agressivo, trata-se com R-CHOP. Linfoma folicular (20%) — indolente, incurável mas de crescimento lento. Linfoma de células do manto (5-7%) — agressivo. Linfoma de Burkitt (2%) — muito agressivo, associado a EBV. Linfoma de células T periférico (10%) — agressivo, CD30+. Tratamento do LDGCB (linfoma B mais comum): R-CHOP — rituximabe 375 mg/m², ciclofosfamida 750 mg/m², doxorrubicina 50 mg/m², vincristina 1,4 mg/m² (máx 2 mg), prednisona 100 mg/dia por 5 dias. Ciclo a cada 21 dias por 6 ciclos. Radioterapia em massa voluminosa (>7,5 cm) ou PET-2 positivo. Profilaxia SNC se sítios de risco (testículo, seio, coluna). R-CHOP cura 60-70% do LDGCB. Índice prognóstico IPI (International Prognostic Index): 5 fatores (idade >60, LDH alto, ECOG ≥2, estadio III/IV, >1 sítio extranodal). Linfoma folicular: Rituximabe isolado (estádio I) ou R-bendamustina. Manutenção com rituximabe. Linfoma de Burkitt: quimioterapia intensiva (CODOX-M/IVAC). Efeitos colaterais: neutropenia febril (G-CSF profilático), alopecia, mucosite, cardiotoxicidade (doxorrubicina).",
                tags = listOf("oncologia", "linfoma não hodgkin", "r-chop", "rituximabe"), citation = "Diretriz NCCN 2023 - LNH"),
            LibraryContentItem(id = "hemato_021", title = "Efeito colateral da doxorrubicina — cardiotoxicidade", category = "CLINICA_MEDICA",
                summary = "Cardiotoxicidade irreversible, dose cumulativa máxima 450-550 mg/m². Prevenir com dexrazoxano.",
                content = "Doxorrubicina (Adriamicina) — Cardiotoxicidade: Mecanismo: formação de radicais livres no miocárdio → lesão de cardiomiócitos → miocardiopatia dilatada (IC irreversível). Tipos: aguda (dias após infusão — arritmias, miopericardite, revertível) e crônica (meses a anos — IC grave, irreversível). Dose cumulativa máxima: 450-550 mg/m² (risco de IC sintomática 5% em 450, 26% em 550, 48% em 700). Fatores de risco: idade >65 ou <4 anos, radioterapia mediastinal prévia, HAS, doença coronariana, disfunção renal, uso concomitante de trastuzumabe. Monitorização: fração de ejeção ventricular esquerda (FEVE) por ecocardiograma ou MUGA — antes da quimioterapia, repetir após cada 2-3 ciclos (se dose cumulativa >400). Se queda de FEVE >10% ou FEVE <50% → suspender. Prevenção: dexrazoxano (quelante de ferro, reduz radicais livres) — indicado na dose cumulativa >300 mg/m². Análogo: epirrubicina — menos cardiotóxico (máx 900-1.000 mg/m²). Lipossomal: reduz cardiotoxicidade mas mantém eficácia (risco menor de IC, efeitos cutâneos — eritrodisestesia palmo-plantar). Tratamento: IC padrão (IECA + BB).",
                tags = listOf("oncologia", "doxorrubicina", "cardiotoxicidade", "antraciclina"), citation = "Diretriz NCCN 2023 - Cardiotoxicidade por Antraciclina"),
            LibraryContentItem(id = "hemato_022", title = "Profilaxia de neutropenia febril — G-CSF", category = "CLINICA_MEDICA",
                summary = "Fator estimulante de colônias (G-CSF — filgrastima, peguifilgrastima) para prevenir neutropenia febril em regimes de alto risco (>20%).",
                content = "Neutropenia febril: temperatura ≥38,3°C ou ≥38°C por >1h, com contagem absoluta de neutrófilos (CAN) <500/mm³. Risco baseado no regime quimioterápico: alto risco (>20%) — CHOP, R-CHOP, ABVD, 7+3. Risco intermediário (10-20%) — carboplatina/taxol, cisplatin/etoposídeo. Baixo risco (<10%) — metotrexato + vincristina, capecitabina. Profilaxia primária com G-CSF: indicada se risco >20%. Filgrastima (G-CSF humano recombinante) 5 mcg/kg/dia SC 24-72h após quimioterapia, até CAN >1.000-2.000. Duração 7-10 dias. Peguifilgrastima (forma peguilada, meia-vida longa) — dose única de 6 mg SC 24-48h após QT (Ciclo a cada 21 dias). Reduz neutropenia febril em 50% e hospitalizações. Efeitos colaterais: dor óssea (analgésicos comuns, AINE), esplenomegalia (raro), SMD/leucemia aguda (risco controverso, se há >6 meses de uso). Tratamento de neutropenia febril estabelecida: ATB empírico de amplo espectro (cefepime, piperacilina-tazobactam, meropenem), hemoculturas, G-CSF não é rotina (evidência controversa em neutropenia febril já instalada).",
                tags = listOf("oncologia", "neutropenia", "g-csf", "filgrastima", "febre"), citation = "Diretriz NCCN 2023 - Neutropenia Febril"),
            LibraryContentItem(id = "hemato_023", title = "Síndrome de lise tumoral", category = "CLINICA_MEDICA",
                summary = "Hiperuricemia, hipercalemia, hiperfosfatemia, hipocalcemia, IRA. Profilaxia: hidratação, alopurinol, rasburicase.",
                content = "Síndrome de Lise Tumoral (SLT): emergência oncológica causada pela lise rápida de células tumorais (geralmente após quimioterapia). Mais comum em: LMA/LNBA, LLA, linfoma de Burkitt, linfoma linfoblástico. Quadro: início em 12-72h após quimioterapia. Alterações laboratoriais: hiperuricemia (≥8 mg/dL), hipercalemia (≥6 mEq/L), hiperfosfatemia (≥4,5 mg/dL), hipocalcemia (secundária à hiperfosfatemia), insuficiência renal aguda (IRA). Classificação Cairo-Bishop: laboratorial (≥2 alterações) ou clínica (laboratorial + Cr >1,5 LSN, arritmia cardíaca, convulsão). Profilaxia (estratificação de risco): baixo risco — hidratação VO/EV + alopurinol 300 mg/dia. Alto risco (LLA, Burkitt, leucemia aguda): hidratação EV (3 L/m²/dia) + alopurinol OU rasburicase (0,15-0,2 mg/kg/dia, especialmente se uricemia elevada). Monitorizar: K+, P, Ca, ácido úrico, Cr a cada 6h durante 24-48h. Tratamento: hidratação agressiva, alopurinol/rasburicase, correção de hipercalemia (insulina+glicose, resinas de troca, bicarbonato se acidose), cálcio EV se hipocalcemia sintomática. Hemodiálise se IRA oligúrica com K+ >6,5 ou uréia >200, ou P >10, ou sobrecarga de volume. Prognóstico: bom se tratado prontamente.",
                tags = listOf("oncologia", "lise tumoral", "uricemia", "rasburicase"), citation = "Diretriz NCCN 2023 - Síndrome de Lise Tumoral"),
            LibraryContentItem(id = "hemato_024", title = "Hipercalcemia maligna — tratamento", category = "CLINICA_MEDICA",
                summary = "Hidratação + bifosfonato (ácido zoledrônico 4 mg IV) + calcitonina. Cálcio >14 mg/dL é emergência.",
                content = "Hipercalcemia maligna: emergência oncológica (cálcio sérico >14 mg/dL ou cálcio ionizado >1,75 mmol/L). Mecanismo: reabsorção óssea por metástases osteolíticas (mama, mieloma, pulmão), ou secreção de PTHrP (carcinoma espinocelular, rim, ovário). Quadro: náusea, vômito, constipação, desidratação, poliúria, letargia, confusão, coma, prolongamento QT, arritmias. Tratamento: 1) Hidratação com SF 0,9% — 200-500 mL/h até corrigir déficit (pode levar 3-6L). 2) Bifosfonato IV — ácido zoledrônico 4 mg IV em 15 min (mais potente, duração 3-4 sem) ou pamidronato 60-90 mg IV em 2h. Efeitos: nefrotoxicidade (ajustar dose na IRC), febre, hipocalcemia, osteonecrose de mandíbula (uso prolongado). 3) Calcitonina 4-8 UI/kg SC/IM 6/12h — ação rápida (2-4h) mas taquifilaxia em 48h. Usar em crises agudas enquanto bifosfonato não fez efeito. 4) Corticoide (prednisona 40-60 mg/dia) — útil em mieloma, linfoma, sarcoidose (↓ produção de 1,25-di-hidroxivitamina D). 5) Denosumabe (anticorpo anti-RANKL) para refratários. Evitar: diuréticos tiazídicos (↑ reabsorção renal de cálcio). Diálise se refratário ou IRA grave. Tratar tumor de base.",
                tags = listOf("oncologia", "hipercalcemia", "bifosfonato", "ácido zoledrônico"), citation = "Diretriz NCCN 2023 - Emergências Oncológicas"),
            LibraryContentItem(id = "hemato_025", title = "Compressão medular neoplásica — emergência", category = "CLINICA_MEDICA",
                summary = "Emergência oncológica: dor nas costas + fraqueza de MMII + perda de esfíncteres. Tratar: dexametasona + radioterapia ou cirurgia.",
                content = "Compressão Medular Metastática (emergência oncológica): mais comum em: mama, pulmão, próstata, mieloma, rim, linfoma (90% são extradural por metástases vertebrais). Quadro clínico: dor na coluna (95% — primeiro sintoma, piora com deitar, piora com esforço/Valsalva), fraqueza motora de MMII (60-80%), perda sensorial (50-70%), disfunção autonômica (retenção/incontinência urinária, constipação — 50-60%). Sinal de Lhermitte (neuropatia). Exame físico: nível sensorial na coluna, hiperreflexia, sinal de Babinski. Diagnóstico: RNM de coluna total com gadolínio (padrão ouro) — deve ser feita URGENTEMENTE se suspeita (não atrasar tratamento para imagem). TC de coluna alternativa (menos sensível). Tratamento (objetivo: prevenir paraplegia permanente): 1) Corticosteróide — dexametasona 10-16 mg IV bolus, depois 4-16 mg 6/6h (alívio rápido da dor e reduz edema). 2) Radioterapia externa (30 Gy em 10 frações) — padrão para a maioria. 3) Cirurgia descompressiva (laminectomia posterior + estabilização) — indicada se: diagnóstico incerto, instabilidade vertebral, radiorresistente (sarcoma, melanoma, renal), progressão durante RT, recidiva pós-RT. Resultado: pacientes que chegam deambulando → 80% mantêm deambulação. Pacientes paraplégicos >24h → <10% recuperam. Prognóstico: melhor se tumor responsivo (mieloma, linfoma, mama, próstata). Dor e sensibilidade preservada são bons sinais. Fraqueza por >48h = pior prognóstico. Tratamento sistêmico (hormonioterapia) se tumor sensível.",
                tags = listOf("oncologia", "compressão medular", "emergência", "dexametasona", "radioterapia"), citation = "Diretriz NCCN 2023 - Emergências Oncológicas"),
        )
    )

    // ═══════════════════════════════════════════════════════════════
    // PACOTE: INFECTOLOGIA — 30 tópicos
