    private val infectoPack = LibraryContentPack(
        source = "[NÃO VERIFICADO] Rascunho gerado por IA — conferir contra: Diretrizes IDSA, MS Brasil, WHO, Surviving Sepsis Campaign",
        items = listOf(
            LibraryContentItem(id = "infecto_001", title = "Sepse — definição atual (qSOFA)", category = "CLINICA_MEDICA",
                summary = "qSOFA ≥2 = suspeita de sepse: alteração da consciência, FR ≥22, PAS ≤100.",
                content = "Sepse — definição SEPSIS-3 (2016): disfunção orgânica ameaçadora à vida causada por resposta desregulada do hospedeiro à infecção. qSOFA (quick SOFA): 3 critérios — alteração do nível de consciência (Glasgow <15), FR ≥22 irpm, PAS ≤100 mmHg. Se ≥2, suspeitar de sepse com mau prognóstico. SOFA completo: 6 sistemas (respiratório, cardiovascular, hepático, coagulação, renal, neurológico). Aumento de ≥2 pontos no SOFA = disfunção orgânica. Choque séptico: sepse com necessidade de vasopressores para manter PAM ≥65 mmHg e lactato >2 mmol/L (apesar de reposição volêmica adequada). Mortalidade: sepse 10-20%, choque séptico >40%. Pacote de 1 hora: medir lactato, coletar hemoculturas, iniciar ATB de amplo espectro, iniciar cristaloides 30 mL/kg se hipotensão/lactato >4, iniciar vasopressor se hipotensão persistente (noradrenalina).",
                tags = listOf("infectologia", "sepse", "qsofa", "definição"), citation = "SSC / Diretriz IDSA 2023 - Sepse"),
            LibraryContentItem(id = "infecto_002", title = "Pacote de 1h da sepse", category = "CLINICA_MEDICA",
                summary = "Hemoculturas + lactato + ATB + cristaloides + vasopressor — tudo em 1 hora.",
                content = "Pacote de 1 hora (Surviving Sepsis Campaign 2021) — iniciar imediatamente em pacientes com sepse/choque séptico: (1) Mensurar lactato: ≥2 mmol/L indica hipoperfusão. Repetir se inicialmente alto. (2) Coletar hemoculturas: 2 pares (aeróbico + anaeróbico) de sítios diferentes, ANTES do ATB (se possível sem atraso >45 min). (3) Iniciar ATB de amplo espectro: cefepime + vancomicina OU meropenem. Individualizar conforme sítio de infecção, patógeno suspeito, resistência local e fatores de risco. (4) Reposição volêmica com cristaloides: 30 mL/kg EV em bolus nas primeiras 3h (se hipotensão ou lactato ≥4 mmol/L). Não usar coloides (hidroxietilamido). (5) Vasopressor: noradrenalina é de primeira escolha. Iniciar se PAM <65 mmHg apesar de reposição volêmica. Acesso venoso central não é necessário para iniciar vasopressor (pode usar periférico temporariamente). Objetivos nas primeiras 6h: PAM ≥65 mmHg, lactato normalizado ou clearance >20%, débito urinário ≥0,5 mL/kg/h. Reavaliação dinâmica da volemia (elevação passiva de pernas, ecocardiografia, variação de volume de pulso).",
                tags = listOf("infectologia", "sepse", "pacote 1h", "ssc"), citation = "SSC 2021 - Sepse"),
            LibraryContentItem(id = "infecto_003", title = "Antibiótico empírico na sepse sem foco", category = "CLINICA_MEDICA",
                summary = "Cefepime + vancomicina OU meropenem (se alto risco de Gram-negativo resistente).",
                content = "Sepse sem foco identificado — tratamento empírico: Cefepime 2g 8/8h + vancomicina 25-30 mg/kg ataque, 15-20 mg/kg manutenção (alvo trough 15-20). Alternativas: piperacilina-tazobactam 4,5g 6/6h + vancomicina. Se alto risco de Gram-negativo resistente (ESBL, Klebsiella pneumoniae carbapenemase — KPC): meropenem 1g 8/8h (ou imipenem 0,5g 6/6h). Se alergia à penicilina: aztreonam 2g 8/8h + vancomicina. Fatores de risco para Gram-negativo resistente: internação recente >5 dias, uso de ATB prévio, colonização conhecida por ESBL/KPC, procedimentos invasivos, imunossupressão. Descalonamento: assim que culturas e identificação de patógeno estiverem disponíveis (48-72h). Duração: 7-10 dias na maioria dos casos (exceto endocardite, osteomielite, infecção de SNC). Avaliar diariamente a suspensão (procalcitonina serial pode guiar — ↓80% ou <0,5 ng/mL sugere parada segura). Mortalidade aumenta 8% para cada hora de atraso do ATB no choque séptico.",
                tags = listOf("infectologia", "sepse", "antibiótico", "empírico"), citation = "SSC 2021 - Sepse"),
            LibraryContentItem(id = "infecto_004", title = "Vasopressor de escolha no choque séptico", category = "CLINICA_MEDICA",
                summary = "Noradrenalina é o vasopressor de primeira linha. Adicionar vasopressina se refratário.",
                content = "Vasopressores no choque séptico: Noradrenalina (norepinefrina) — vasopressor de 1ª escolha. Iniciar 0,05-0,5 mcg/kg/min, titular para PAM ≥65 mmHg. Mecanismo: agonista α-1 e β-1. Se noradrenalina em doses altas (>0,5 mcg/kg/min) e PAM não atinge meta: adicionar vasopressina 0,03-0,04 U/min (sem titulação). Alternativa (2ª linha): adrenalina 0,05-0,5 mcg/kg/min (quando noradrenalina + vasopressina não bastam). Dobutamina 2,5-20 mcg/kg/min: considerar se disfunção miocárdica (débito cardíaco baixo) apesar de noradrenalina. Nunca usar dopamina como primeira escolha (↑ arritmias, ↑ mortalidade vs noradrenalina). Meta: PAM ≥65 mmHg inicialmente (individualizar se HAS crônica — pode precisar PAM ≥75). Não usar vasopressores sem reposição volêmica adequada. Cuidados: acesso venoso periférico pode ser usado temporariamente (monitorizar extravasamento). Se refratário, considerar hidrocortisona 50 mg 6/6h (se PAS <50 apesar de noradrenalina).",
                tags = listOf("infectologia", "choque séptico", "noradrenalina", "vasopressor"), citation = "SSC 2021 - Sepse"),
            LibraryContentItem(id = "infecto_005", title = "Avaliação do lactato na sepse", category = "CLINICA_MEDICA",
                summary = "Lactato arterial normal <2 mmol/L. >2 = hipoperfusão. >4 = choque. Clearance de lactato >20% em 6h = boa resposta.",
                content = "Lactato na sepse: Marcador de hipoperfusão tecidual e prognóstico. Normal: <2 mmol/L (<18 mg/dL). Hiperlactatemia: 2-4 mmol/L indica hipoperfusão (demanda > oferta de O2). >4 mmol/L = choque tissular (associado a mortalidade 3x maior). Causas: tipo A (hipóxia tecidual — sepse, choque, hemorragia, IAM) e tipo B (sem hipóxia — enzimas hepáticas, álcool, hepatite, tiamina deficiência, medicações — metformina, propofol, adrenalina). Clearance de lactato (melhor prognóstico): lactato inicial - lactato de 6h / lactato inicial × 100. >20% de queda em 6h = boa resposta (mortalidade 10%). <20% de queda ou piora = pior prognóstico (mortalidade 40-50%). A lactatemia não deve ser usada isoladamente para decisão — integrar com sinais vitais, débito urinário e ecocardiografia. Ringer lactato é seguro na sepse (não piora acidose lática) — preferível ao SF 0,9% (evita acidose hiperclorêmica e lesão renal aguda).",
                tags = listOf("infectologia", "lactato", "sepse", "prognóstico"), citation = "SSC 2021 - Sepse"),
            LibraryContentItem(id = "infecto_006", title = "Dengue — classificação (A, B, C, D)", category = "CLINICA_MEDICA",
                summary = "Classificação OMS: grupo A (ambulatorial), B (comorbidades), C (sinais de alarme), D (dengue grave).",
                content = "Classificação de gravidade da Dengue (OMS 2009, adotada no Brasil): Grupo A — febre + exantema + mialgia, sem hemorragia, sem comorbidades, sem sinais de alarme. Prova do laço pode ser positiva. Manejo: ambulatorial, hidratação oral (>60 mL/kg/dia). Grupo B (comorbidades): extremos de idade (<2 ou >65), gestante, HAS, DM, DRC, asma, uso de AAS. Manejo: observação por 24-48h para sinais de alarme. Grupo C (sinais de alarme): dor abdominal intensa e contínua, vômitos persistentes, extravasamento plasmático (ascite, derrame pleural), sangramento mucosa, hepatomegalia >2 cm, aumento Ht >20%, hipotensão postural, irritabilidade/letargia. Manejo: internação, hidratação EV (Ringer lactato 5-10 mL/kg/h nas primeiras 2-4h, depois reduzir). Grupo D (dengue grave): choque, sangramento grave (melena, hematêmese, SNC), disfunção orgânica (IRA, encefalite, miocardite). Manejo: UTI, hidratação EV agressiva (20 mL/kg em 30 min, repetir até 3x), hemotransfusão se sangramento grave. Evitar AINEs, AAS, corticoides. Controle rigoroso de Ht, sinais vitais, débito urinário. Reposição de plaquetas não é rotina (transfundir apenas se sangramento ativo + plaquetas <20.000).",
                tags = listOf("infectologia", "dengue", "classificação", "sinais de alarme"), citation = "Diretriz MS Brasil 2023 - Dengue"),
            LibraryContentItem(id = "infecto_007", title = "Prova do laço na dengue", category = "CLINICA_MEDICA",
                summary = "Prova do laço positiva (>20 petéquias em 5x5cm) indica fragilidade capilar. Pode indicar maior risco de evolução para forma grave.",
                content = "Prova do laço na dengue: técnica — medir PA, insuflar o manguito no ponto médio entre PA sistólica e diastólica por 5 minutos (crianças 3 min) ou até que apareçam petéquias. Marcar um quadrado de 2,5 cm x 2,5 cm (5 cm²) no antebraço, 4 cm abaixo da prega do cotovelo. Contar petéquias. POSITIVA se: ≥20 petéquias em adultos, ≥10 em crianças. A prova do laço positiva indica fragilidade capilar (trombocitopenia e/ou disfunção plaquetária). Na classificação: grupos A e B — prova do laço pode ser positiva. Grupo A com prova do laço negativa sem comorbidades → manejo ambulatorial. Prova do laço positiva reforça diagnóstico de dengue mas não é critério isolado para internação (avaliar outros sinais). Pode ser negativa nas primeiras 24-48h de febre e positiva depois. Limitação: baixa especificidade (pode ser positiva em outras doenças febris). Não usar se o paciente já tem petéquias espontâneas ou sangramento — já caracteriza grupo C/D.",
                tags = listOf("infectologia", "dengue", "prova do laço", "sangramento"), citation = "Diretriz MS Brasil 2023 - Dengue"),
            LibraryContentItem(id = "infecto_008", title = "Tratamento da dengue grave", category = "CLINICA_MEDICA",
                summary = "Hidratação venosa rigorosa (Ringer lactato) com monitorização de Ht e sinais vitais. Transfusão se sangramento grave.",
                content = "Dengue grave (grupo D) — manejo: Reposição volêmica: Ringer lactato (preferível ao SF 0,9%) 20 mL/kg em 20-30 min. Reavaliar sinais vitais, Ht, perfusão. Se melhora, repetir 1-2x (máx 60 mL/kg em 1h). Se choque refratário: considerar albumina ou plasma. Após estabilização: reduzir para 10 mL/kg/h e titular conforme diurese (alvo 0,5-2 mL/kg/h) e Ht (<45-50%). Não usar expansores baseados em Ht isolado (Ht elevado indica hemoconcentração — precisa de volume; Ht em queda + instável = sangramento → precisa de transfusão). Transfusão de concentrado de hemácias: se sangramento ativo + Ht em queda rápida (mesmo >30%) ou se Ht <30 (choque) com hemoconcentração resolvida. Plaquetas: não transfundir profilaticamente (mesmo se <10.000). Transfundir apenas se sangramento ativo + plaquetas <20.000. Corticosteroides: não usar (aumenta complicações). Evitar AAS, AINEs, IECA, diuréticos. Monitorizar: PA a cada 15-30 min, Ht a cada 2-4h, diurese horária, oximetria. Alta: 24-48h sem febre, Ht estável sem hidratação EV, débito urinário normal, sem desconforto respiratório.",
                tags = listOf("infectologia", "dengue grave", "hidratação", "choque"), citation = "Diretriz MS Brasil 2023 - Dengue"),
            LibraryContentItem(id = "infecto_009", title = "Febre chikungunya — artralgia intensa", category = "CLINICA_MEDICA",
                summary = "Artralgia intensa e prolongada (meses/anos). Tratamento sintomático: AINEs, corticoides (fase crônica). Evitar AAS.",
                content = "Febre Chikungunya: Arbovirose (Aedes aegypti/albopictus). Quadro clínico: febre alta súbita (>39°C) + poliartralgia simétrica intensa (mãos, punhos, joelhos, tornozelos) + exantema maculopapular. Diferencial: a artralgia é MUITO mais intensa que na dengue. Fases: aguda (3-10 dias), subaguda (10-30 dias), crônica (>3 meses — 30-60% evoluem com artralgia persistente por meses a anos). Diagnóstico: sorologia (IgM a partir do 3º dia) ou PCR (fase aguda). Tratamento: Fase aguda — sintomáticos: dipirona, paracetamol (evitar AAS!). Repouso, hidratação. Fase subaguda/crônica: AINEs (ibuprofeno 600 mg 8/8h, naproxeno 500 mg 12/12h), fisioterapia. Se artralgia intensa >3 meses: considerar corticoide (prednisona 10-20 mg/dia desmame 6-12 sem), metotrexato, hidroxicloroquina (evidência limitada). Avaliar reumatologista se artralgia crônica incapacitante. Prevenção: combate ao vetor, repelente. Não tem tratamento antiviral específico. Chikungunya grave: manifestações atípicas (encefalite, miocardite, nefrite) — mais em recém-nascidos, idosos, comorbidades.",
                tags = listOf("infectologia", "chikungunya", "artralgia", "aade"), citation = "Diretriz MS Brasil 2023 - Febre Chikungunya"),
            LibraryContentItem(id = "infecto_010", title = "Zika — associação com microcefalia", category = "CLINICA_MEDICA",
                summary = "Microcefalia em RN de gestantes infectadas. Diagnóstico: RT-PCR no sangue/urina (até 7 dias). Tratamento: sintomático.",
                content = "Zika vírus: Flavivírus (Aedes aegypti). Quadro agudo: febre baixa, exantema maculopapular pruriginoso, artralgia leve, conjuntivite não purulenta (diferencial: olho vermelho + prurido + artralgia = Zika). Na maioria, assintomático (80%). Diagnóstico: RT-PCR no sangue (até 5 dias) e urina (até 7-10 dias) — o vírus persiste mais tempo na urina. Sorologia IgM (cruzamento com dengue — difícil interpretação). Gestantes: coleta de sangue e urina para RT-PCR mesmo que assintomáticas durante surto. Complicações: Síndrome de Guillain-Barré (associação temporal). Síndrome congênita: microcefalia (nascimento com PC <2 DP abaixo da média), calcificações intracranianas, anomalias oculares, artrogripose. Risco maior se infecção no 1º trimestre. Não há tratamento antiviral. Manejo: sintomáticos (anti-histamínicos para prurido, paracetamol para febre). Evitar AAS e AINEs (risco de síndrome hemorrágica — até descartar dengue). Prevenção em gestantes: repelente, roupas compridas, evitar áreas de surto, abstinência sexual ou uso de preservativo (transmissão sexual possível por até 3 meses). Notificação compulsória.",
                tags = listOf("infectologia", "zika", "microcefalia", "gestante"), citation = "Diretriz MS Brasil 2023 - Zika Vírus"),
            LibraryContentItem(id = "infecto_011", title = "Malária — diagnóstico", category = "CLINICA_MEDICA",
                summary = "Gota espessa ou teste rápido. Tratamento: artemeter-lumefantrina (P. falciparum) ou cloroquina (P. vivax/ovale).",
                content = "Malária (Plasmodium): transmitida por Anopheles. Diagnóstico padrão ouro: gota espessa (visualização direta do parasita, permite quantificação e identificação da espécie). Coloração de Giemsa. Teste rápido (TR) — detecta antígeno (HRP-2 para falciparum, pLDH para todas). Sensibilidade >90% na malária sintomática. Espécies e tratamento: P. vivax (mais comum no Brasil) — cloroquina 25 mg/kg em 3 dias + primaquina 0,5 mg/kg/dia por 7-14 dias (esquema radical para eliminar hipnozoítos). P. falciparum — artemeter-lumefantrina (Coartem) 6 doses em 3 dias (padrão ouro artemisinina combinada — ACT). Alternativa: artesunato + mefloquina. P. malariae — cloroquina. P. ovale — cloroquina + primaquina. Malária grave (critérios OMS): qualquer um de — coma (malária cerebral), anemia grave (Hb <5), IRA, SDRA, hipoglicemia, acidose, hiperparasitemia (>5% em não-imune), icterícia, disfunção orgânica. Tratamento da malária grave: artesunato EV 2,4 mg/kg (ataque, repetir 12h e 24h, depois 1x/dia) ou quinino IV (se indisponível artesunato). Medidas de suporte: manejo da glicemia, convulsões, hidratação, diálise se IRA. Notificação compulsória.",
                tags = listOf("infectologia", "malária", "gota espessa", "artemeter", "cloroquina"), citation = "Diretriz MS Brasil 2023 - Malária"),
            LibraryContentItem(id = "infecto_012", title = "Malária grave — tratamento", category = "CLINICA_MEDICA",
                summary = "Artesunato EV 2,4 mg/kg (ataque, 12h, 24h, depois 1x/dia). Alternativa: quinino IV. Suporte em UTI.",
                content = "Malária grave (critérios OMS): Tratamento de escolha: artesunato EV (Age Care) 2,4 mg/kg IV em bolus lento — dose inicial (hora 0), repetir 12h e 24h depois, continuar 1x/dia até poder tomar VO (total 3-7 dias). Fornecido gratuitamente pelo MS Brasil (tratamento de toda malária grave em hospitais públicos). Se indisponível: Quinino (dose de ataque 20 mg/kg IV em 4h, depois 10 mg/kg 8/8h em 4h) + doxiciclina 100 mg 12/12h ou clindamicina. Medidas de suporte: monitorizar glicemia (quinino estimula insulina → hipoglicemia), convulsões (diazepam), anemia grave (transfusão se Hb <7 ou sinais de insuficiência cardíaca), IRA (diálise se necessário), acidose metabólica. Malária cerebral: coma (Glasgow <11), convulsões, edema cerebral. Manejo: manter cabeceira 30º, controle de convulsões, evitar glicocorticoides (pioram prognóstico). Troca de plasma (exchange transfusion) se parasitemia >10% + disfunção orgânica. Mortalidade da malária cerebral: 15-20%. Pode deixar sequelas neurológicas (10%). Transição para VO assim que tolerar: artemeter-lumefantrina ou quinino + doxiciclina (total 7 dias).",
                tags = listOf("infectologia", "malária grave", "artesunato", "paludismo"), citation = "Diretriz MS Brasil 2023 - Malária Grave"),
            LibraryContentItem(id = "infecto_013", title = "Doença de Chagas — tratamento", category = "CLINICA_MEDICA",
                summary = "Benzonidazol 5 mg/kg/dia por 60 dias (adultos) — eficaz na fase aguda e crônica recente (<50 anos sem cardiopatia avançada).",
                content = "Doença de Chagas (Trypanosoma cruzi): transmissão vetorial (Triatoma infestans barbeiro), congênita, oral (açaí contaminado), transfusional. Diagnóstico: fase aguda — parasitemia visível (exame de gota espessa, PCR). Fase crônica — sorologia (ELISA + IFI ou quimioluminescência). Tratamento: Benzonidazol 5 mg/kg/dia (máx 300 mg/dia) VO, 12/12h, por 60 dias. Efeitos colaterais: dermatite (30-50% — rash cutâneo), neuropatia periférica (10-30% — parestesias, suspender se progressiva), anorexia, náusea. Indicações obrigatórias: fase aguda (qualquer idade), reativação (HIV, imunossupressão), crianças <12 anos, crônica recente (<50 anos sem cardiopatia avançada). Contraindicado: cardiopatia chagásica avançada (ICC classe III/IV, megaesôfago avançado), gestação, IRC. Tratamento na fase crônica (>50 anos ou cardiopatia estabelecida): controvérsia — tratar apenas se miocardite ativa (PCR+/sorologia +), ou não tratar (benefício incerto, risco de efeitos adversos). Tratamento sintomático da cardiopatia chagásica: IECA + BB na IC, amiodarona para arritmia ventricular (marca-passo se necessário), transplante cardíaco (evitar, mas possível). Prevenção: controle de vetores, doação de sangue, triagem pré-natal. Transmissão oral (açaí): cozinhar açaí por 1 minuto a 80°C elimina o parasita.",
                tags = listOf("infectologia", "chagas", "benzonidazol", "cardiomiopatia"), citation = "Diretriz MS Brasil 2023 - Doença de Chagas"),
            LibraryContentItem(id = "infecto_014", title = "Leishmaniose visceral — tratamento", category = "CLINICA_MEDICA",
                summary = "Anfotericina B lipossomal 3-5 mg/kg/dia por 5-7 dias ou antimonial pentavalente (Glucantime) 20 mg Sb⁵⁺/kg/dia IM/IV por 20 dias.",
                content = "Leishmaniose visceral (Calazar — Leishmania chagasi/infantum): transmitida por flebótomo (Lutzomyia). Quadro: febre irregular prolongada, hepatoesplenomegalia maciça, pancitopenia (anemia, leucopenia, plaquetopenia), perda de peso, palidez, adenomegalia. Sinais de alerta: febre >3 sem + hepatoesplenomegalia + pancitopenia. Diagnóstico: teste rápido (rK39) — alta sensibilidade na LV. Mielograma com amastigotas (padrão ouro). PCR. Tratamento de primeira escolha: Anfotericina B lipossomal (preferível — menos tóxica, mais eficaz) 3-5 mg/kg/dia IV por 5-7 dias (dose total 18-21 mg/kg). Se indisponível: Desoxicolato de anfotericina B 1 mg/kg/dia IV em dias alternados por 20 dias (monitorizar Cr, K+, Mg). Antimonial pentavalente (Glucantime — N-metil-glucamina) 20 mg Sb5+/kg/dia IM ou IV (máx 15 mL/dia) por 20-30 dias. Contraindicações: arritmia cardíaca, hepatopatia, insuficiência renal. Efeitos: cardiotoxicidade (prolongamento QT), pancreatite, artralgia, mialgia, elevação de enzimas hepáticas. Miltefosina 100 mg/dia VO por 28 dias — alternativa oral (teratogênica, evite mulheres em idade fértil sem contracepção). Co-infecção HIV: tratamento prolongado, profilaxia secundária (anfotericina lipossomal mensal). Mortalidade: <5% se tratada precocemente, até 20% se tardia.",
                tags = listOf("infectologia", "leishmaniose visceral", "calazar", "anfotericina"), citation = "Diretriz MS Brasil 2023 - Leishmaniose Visceral"),
            LibraryContentItem(id = "infecto_015", title = "Leishmaniose tegumentar — tratamento", category = "CLINICA_MEDICA",
                summary = "Antimonial pentavalente (Glucantime) 10-20 mg Sb⁵⁺/kg/dia IM por 20-30 dias para forma cutânea.",
                content = "Leishmaniose Tegumentar Americana (LTA): causada por várias espécies (L. braziliensis, L. guyanensis, L. amazonensis). Formas clínicas: cutânea (úlcera indolor com bordas elevadas, fundo granuloso), mucosa (lesão no septo nasal, boca, faringe — pode destruir estruturas), cutânea disseminada (múltiplas lesões). Tratamento: Antimonial pentavalente (Glucantime — N-metil-glucamina) 10-20 mg Sb5+/kg/dia IM (máx 3 ampolas de 5 mL/dia) por 20 dias (forma cutânea), 30 dias (forma mucosa). Efeitos colaterais: reversíveis — cardiotoxicidade (QT), hepatotoxicidade, pancreatite, artralgia, mialgia. ECG antes e após 10 dias de tratamento. Contraindicações: arritmia, cardiopatia, IRC, hepatopatia, gestação. Alternativas: anfotericina B lipossomal 2-3 mg/kg/dia por 10 dias (preferível em: cardiopatas, gestantes, insuficiência renal, idosos, casos refratários). Pentamidina (L. guyanensis) 300 mg/kg IM em 3 doses em dias alternados. Miltefosina 100 mg/dia por 28 dias — oral, eficaz, mas cara. Tratamento tópico: não existe eficaz (paromomicina tópica — disponível em pesquisa). Acompanhamento: critério de cura — epitelização completa da úlcera até 3 meses após tratamento.",
                tags = listOf("infectologia", "leishmaniose tegumentar", "glucantime", "úlcera"), citation = "Diretriz MS Brasil 2023 - Leishmaniose Tegumentar"),
            LibraryContentItem(id = "infecto_016", title = "HIV — carga viral e CD4", category = "CLINICA_MEDICA",
                summary = "CD4 <200 células/mm³ define AIDS. Carga viral monitora resposta à TARV. Supressão viral: <50 cópias/mL.",
                content = "HIV: Monitoramento: Contagem de CD4 (células T helper) — nível de imunidade. Normal: 500-1.500 células/mm³. CD4 <200 define AIDS (síndrome da imunodeficiência adquirida) — alto risco de infecções oportunistas. CD4 <50 — risco de infecções por CMV, micobactérias não tuberculosas, criptosporidiose. Carga viral (CV) — cópias de RNA-HIV/mL. Meta da TARV: supressão viral sustentada (<50 cópias/mL). Após início da TARV, espera-se queda de 1 log em 1 mês e <50 em 3-6 meses. CV acima de 50 = viremia residual. Acima de 200 = falha virológica (confirmar com 2ª amostra). Lembrar: transmissão sexual zero se CV <200 (U=U — Undetectable = Untransmittable). Coleta: CD4 e CV a cada 3-6 meses se estável (CV <50). Se falha virológica (rebote de CV), investigar adesão, interações, resistência (genotipagem). Atenção: CD4 não é mais necessário para iniciar TARV (iniciar TARV em todos, independentemente de CD4). O CD4 é usado para decidir profilaxias (Pneumocystis, Toxoplasma, MAC) e monitorizar resposta imunológica.",
                tags = listOf("infectologia", "hiv", "cd4", "carga viral", "tarav"), citation = "Diretriz MS Brasil 2023 - HIV/AIDS"),
            LibraryContentItem(id = "infecto_017", title = "Esquema TARV inicial no Brasil", category = "CLINICA_MEDICA",
                summary = "TLD: tenofovir (300 mg) + lamivudina (300 mg) + dolutegravir (50 mg) — 1 comprimido/dia.",
                content = "Esquema TARV inicial no Brasil (MS 2023): Esquema preferencial: TLD — Tenofovir (TDF) 300 mg + Lamivudina (3TC) 300 mg + Dolutegravir (DTG) 50 mg, 1 cp VO 1x/dia. Vantagens: dose única diária, perfil de resistência alto, bem tolerado. Efeitos colaterais iniciais (primeiras 2-4 semanas): cefaleia, insônia, náusea (passam com tempo). Ganho de peso (5-10% dos pacientes, principalmente com DTG). Contraindicações: IRC (TFG <50 — ajustar ou evitar TDF, preferir tenofovir alafenamida — TAF). Interação: evitar DTG com anticonvulsivantes indutores (carbamazepina, fenitoína, fenobarbital — reduz níveis de DTG). Alternativa 1: TAF + FTC + DTG (em vez de TDF) — em perda de densidade óssea, IRC ou idosos. Alternativa 2: TDF + 3TC + Efavirenz (EFZ) 600 mg/dia — quando DTG não puder ser usado (gestação 1º trimestre? — DTG é seguro, mas EFV ainda é alternativa). Efeitos de EFZ: sonhos vívidos, insônia, tontura (primeiras 2-4 semanas), depressão, risco de suicídio. Iniciar TARV: o mais rápido possível, independente de CD4. Avaliar antes: função renal (Cr, uréia), β-HCG (se mulher), genotipagem pré-tratamento se disponível. Teste de HLA-B*5701 antes de abacavir (não usado no TLD).",
                tags = listOf("infectologia", "hiv", "tarav", "dolutegravir", "tenofovir"), citation = "Diretriz MS Brasil 2023 - HIV/AIDS"),
            LibraryContentItem(id = "infecto_018", title = "Profilaxia primária para Pneumocystis", category = "CLINICA_MEDICA",
                summary = "TMP-SMX (800/160 mg 3x/semana ou 1x/dia) quando CD4 <200 células/mm³.",
                content = "Profilaxia primária para Pneumocystis jirovecii (PCP): Indicada se CD4 <200 células/mm³ (em pacientes com HIV). Esquema: TMP-SMX (sulfametoxazol + trimetoprima) 800/160 mg (1 comprimido duplo) VO 3x/semana em dias alternados, ou 1 comprimido simples 1x/dia. Alternativas quando TMP-SMX não é tolerado (alergia, neutropenia, hipercalemia): dapsona 100 mg/dia (testar G6PD antes!) ou atovaquona 750 mg 2x/dia, ou pentamidina aerossol 300 mg/mês (menos eficaz, reserva). Prevenção secundária: após episódio de PCP, manter profilaxia até CD4 >200 por ≥3 meses e CV <50. Efeitos colaterais do TMP-SMX: hipercalemia, neutropenia, rash cutâneo (leve a Stevens-Johnson), aumento de Cr, náusea. Se rash leve não bolhoso: tentar dessensibilização. PCP (pneumocistose): febre, dispneia, tosse seca, hipoxemia. Rx tórax: infiltrado intersticial bilateral difuso (padrão em vidro fosco). Diagnóstico: lavado broncoalveolar (LBA) com coloração de Grocott. β-D-glucana sérica elevada. Tratamento: TMP-SMX EV 15-20 mg/kg/dia (componente TMP) 6/6h ou 8/8h por 14-21 dias. Corticoide se PaO2 <70 mmHg (prednisona 40 mg 2x/dia).",
                tags = listOf("infectologia", "hiv", "profilaxia", "pneumocystis", "tmp-smx"), citation = "Diretriz MS Brasil 2023 - HIV/AIDS"),
            LibraryContentItem(id = "infecto_019", title = "Profilaxia para toxoplasmose", category = "CLINICA_MEDICA",
                summary = "TMP-SMX 800/160 mg 1x/dia quando CD4 <100 e IgG anti-toxoplasma +.",
                content = "Profilaxia primária para Toxoplasmose cerebral (T. gondii): Indicada se CD4 <100 células/mm³ + sorologia IgG anti-toxoplasma positiva. Se IgG negativa: orientar evitar carne crua/mal passada e fezes de gato. Esquema: TMP-SMX 800/160 mg VO 1x/dia (ou 3x/semana). Alternativa: dapsona 50 mg/dia + pirimetamina 50 mg/semana + ácido folínico 25 mg/semana. Efeitos colaterais: TMP-SMX (ver acima). Prevenção secundária: após toxoplasmose cerebral, manter profilaxia até CD4 >200 por ≥6 meses com CV <50. Toxoplasmose cerebral: cefaleia + confusão + convulsão + déficit focal + febre. Diagnóstico: RNM de crânio com múltiplas lesões anelares captantes de gadolínio nos gânglios da base. Hemisfério cerebral, cerebelo. Sorologia IgG + (quase sempre), IgM geralmente negativa (reativação). PCR para toxoplasma no LCR (se disponível). Tratamento: sulfadiazina 1,5-2g 6/6h + pirimetamina 50 mg/dia + ácido folínico 10-25 mg/dia (profilaxia de toxicidade hematológica). Alternativa: TMP-SMX EV ou atovaquona + pirimetamina. Duração: 6 semanas mín. Corticoide (dexametasona) se edema cerebral significativo. Se falha (progressão clínica e radiológica em 2 semanas): substituir sulfadiazina por clindamicina (pirimetamina + clindamicina).",
                tags = listOf("infectologia", "hiv", "toxoplasmose", "profilaxia", "tmp-smx"), citation = "Diretriz MS Brasil 2023 - HIV/AIDS"),
            LibraryContentItem(id = "infecto_020", title = "Sífilis — diagnóstico e tratamento", category = "CLINICA_MEDICA",
                summary = "VDRL para rastreio e seguimento. FTA-Abs confirma. Penicilina G benzatina: doses conforme estágio.",
                content = "Sífilis (Treponema pallidum): Diagnóstico: testes treponêmicos (FTA-Abs, TPHA, ELISA) — confirmam contato prévio (ficam + para sempre). Testes não treponêmicos (VDRL, RPR) — usados para rastreio e seguimento (quantitativos, caem com tratamento). VDRL positivo em diluições ≥1:16 sugere atividade. Tratamento: Sífilis primária (cancro duro) e secundária (exantema palmo-plantar, condiloma lata): Penicilina G benzatina 2,4 milhões UI IM, dose única (1,2 milhão em cada glúteo). Sífilis latente precoce (<1 ano): mesma dose única. Sífilis latente tardia (>1 ano ou duração ignorada) e terciária (goma, neurossífilis, aortite): Penicilina G benzatina 2,4 milhões UI IM 1x/semana por 3 semanas (total 7,2 milhões UI). Neurossífilis: Penicilina G cristalina 18-24 milhões UI/dia EV (em 4 doses 6/6h) por 14 dias. Reação de Jarisch-Herxheimer (febre, mialgia, cefaleia 6-12h após penicilina) — tratar com sintomáticos. Acompanhamento: VDRL quantitativo mensal (deve cair 4x em 6 meses e negativar em 12-24 meses). Alergia à penicilina: dessensibilizar (gestantes: apenas penicilina trata sífilis congênita). Doxiciclina 100 mg 2x/dia por 14 dias (latente tardia 28 dias) ou ceftriaxona 1g/dia IM por 10-14 dias são alternativas (mas não para gestantes).",
                tags = listOf("infectologia", "sífilis", "penicilina", "vdrl"), citation = "Diretriz MS Brasil 2023 - Sífilis"),
            LibraryContentItem(id = "infecto_021", title = "Sífilis congênita — tratamento", category = "CLINICA_MEDICA",
                summary = "Penicilina G cristalina 50.000 UI/kg/dose a cada 12h (<7 dias) ou 8h (≥7 dias) por 10 dias.",
                content = "Sífilis congênita: transmissão transplacentária de T. pallidum. Risco maior no 2º e 3º trimestres. Prevenção: tratamento adequado da gestante com penicilina G benzatina (único tratamento eficaz para prevenir sífilis congênita). Tratamento inadequado (outro antibiótico, dose errada, intervalo >14 dias entre doses) não previne. Acompanhamento do recém-nascido: VDRL sérico (RN com títulos 4x maior que o materno indica infecção ativa). Exame físico: rinite serossanguinolenta, exantema, hepatoesplenomegalia, periostite, pseudo-paralisia de Parrot (ossos longos). Exames: VDRL sérico quantitativo, hemograma, plaquetas, radiografia de ossos longos, análise de LCR (VDRL, células, proteínas), fundo de olho, BERA. Tratamento RN: Penicilina G cristalina 50.000 UI/kg/dose IV a cada 12h (idade <7 dias) ou a cada 8h (≥7 dias), por 10 dias. Se LCR alterado (VDRL+) ou Rx alterado: tratamento completo por 10 dias. Se assintomático com exames normais: penicilina G benzatina 50.000 UI/kg IM dose única (alternativa). Acompanhamento: VDRL seriado a cada 3 meses por 18 meses. VDRL deve negativar em 6-12 meses. Se títulos aumentarem ou não caírem, retratar. Alta: todos os RN de mãe com VDRL+ tratado — seguimento obrigatório. Notificação compulsória.",
                tags = listOf("infectologia", "sífilis congênita", "penicilina", "rn"), citation = "Diretriz MS Brasil 2023 - Sífilis Congênita"),
            LibraryContentItem(id = "infecto_022", title = "Gonorreia — tratamento", category = "CLINICA_MEDICA",
                summary = "Ceftriaxona 500 mg IM + azitromicina 1g VO dose única (esquema dual).",
                content = "Gonorreia (Neisseria gonorrhoeae): Tratamento de primeira linha: Ceftriaxona 500 mg IM dose única + Azitromicina 1g VO dose única (terapia dupla — cobre clamídia concomitante e reduz resistência). Alternativa se alergia a cefalosporina: Gentamicina 240 mg IM dose única + Azitromicina 2g VO. Gonorreia disseminada (artrite, tenossinovite, dermatite pustulosa): Ceftriaxona 1g IV 1x/dia + Azitromicina 1g VO dose única, depois cefixima 400 mg VO 2x/dia para completar 7-14 dias de tratamento. Resistência: N. gonorrhoeae desenvolveu resistência a penicilinas, tetraciclinas, fluoroquinolonas. Cefalosporinas são a última classe com eficácia consistente. Casos suspeitos de resistência: fazer cultura + teste de sensibilidade. Reportar ao MS. Tratar parceiro sexual (ceftriaxona + azitromicina). Abstinência sexual por 7 dias após tratamento. Teste de cura (test of cure): apenas se persistência de sintomatologia ou suspeita de resistência. Acompanhamento: repetir sorologia para HIV e sífilis (alta prevalência de co-infecção). Notificar todos os casos ao MS.",
                tags = listOf("infectologia", "gonorreia", "ceftriaxona", "ist"), citation = "Diretriz MS Brasil 2023 - IST"),
            LibraryContentItem(id = "infecto_023", title = "Clamídia — tratamento", category = "CLINICA_MEDICA",
                summary = "Azitromicina 1g VO dose única ou doxiciclina 100 mg 12/12h por 7 dias.",
                content = "Clamídia (Chlamydia trachomatis): infecção sexualmente transmissível mais comum no mundo. Na mulher: frequentemente assintomática (70-80%), corrimento mucopurulento, cervicite, sangramento pós-coito, disúria. Complicações: doença inflamatória pélvica (DIP), infertilidade tubária, gravidez ectópica, dor pélvica crônica. No homem: uretrite com disúria, corrimento uretral claro/mucopurulento. Recém-nascido: conjuntivite neonatal (3-14 dias), pneumonia afebril (2-12 semanas). Tratamento: Azitromicina 1g VO dose única (1cp de 1g) — não requer adesão prolongada, cobre uretrite/cervicite. Alternativa: Doxiciclina 100 mg VO 12/12h por 7 dias (mais eficaz em infecção retal? — sim, prefira para homens que fazem sexo com homens). Clamídia complicada (DIP, epididimite): Ceftriaxona 500 mg IM + Doxiciclina 100 mg 12/12h VO por 14 dias (com ou sem metronidazol). Gestantes: Azitromicina 1g dose única (doxiciclina contraindicada). Parceiro: tratar nos últimos 60 dias. Abstinência sexual por 7 dias após tratamento. Teste de cura (test of cure): recomendado em gestantes (3-4 semanas após) ou se sintomas persistentes. Repetir sorologias (HIV, sífilis).",
                tags = listOf("infectologia", "clamídia", "azitromicina", "ist"), citation = "Diretriz MS Brasil 2023 - IST"),
            LibraryContentItem(id = "infecto_024", title = "Tricomoníase — tratamento", category = "CLINICA_MEDICA",
                summary = "Metronidazol 2g VO dose única (parceiro e parceira simultaneamente). Alternativa: tinidazol 2g dose única.",
                content = "Tricomoníase (Trichomonas vaginalis): IST muito comum, frequentemente assintomática. Mulher: corrimento amarelo-esverdeado bolhoso, odor fétido, prurido vulvar, dispareunia, colo em framboesa. Homem: geralmente assintomático, uretrite leve, disúria. Diagnóstico: exame a fresco (visualização do protozoário móvel em salina), cultura (padrão ouro), PCR. Teste rápido de antígeno. Tratamento: Metronidazol 2g VO dose única (ambos os parceiros simultaneamente). Alternativa: Tinidazol 2g VO dose única (menos náusea, mesma eficácia). Se falha: Metronidazol 500 mg 2x/dia por 7 dias. Efeitos colaterais: gosto metálico na boca, náusea, disgeusia. Interação com álcool: efeito dissulfiram (náusea, vômito, rubor, taquicardia) — proibir álcool durante o tratamento e 24h após (48h para tinidazol). Gestantes: Metronidazol 2g dose única é seguro (categoria B) — tratar todas gestantes sintomáticas (associada a parto prematuro, baixo peso). Consenso: assintomática na gestação — pode tratar (reduz complicações). Controvérsia: tratar ou não? MS Brasil: tratar apenas se sintomática. Repetir teste de cura (test of cure) 3-4 semanas após se gestante ou suspeita de falha. Abstinência sexual até conclusão do tratamento. Rastreio: HIV, sífilis.",
                tags = listOf("infectologia", "tricomoníase", "metronidazol", "ist"), citation = "Diretriz MS Brasil 2023 - IST"),
            LibraryContentItem(id = "infecto_025", title = "Tuberculose em HIV — tratamento", category = "CLINICA_MEDICA",
                summary = "RIPE (esquema TB) + TARV (iniciar 2-8 semanas após RIPE). Profilaxia com TMP-SMX se CD4 <200.",
                content = "Tuberculose em HIV (coinfecção TB-HIV): Tratamento da TB: RIPE igual ao HIV negativo (rifampicina, isoniazida, pirazinamida, etambutol por 2 meses, depois R+H por 4 meses). A rifampicina é potente indutor enzimático → ajustar TARV (↑ dose de dolutegravir para 50 mg 2x/dia se peso >30 kg ou alternativas: preferir TDF + 3TC + EFV 600 mg 2x/dia). Quando iniciar TARV: se CD4 <50: iniciar TARV 2 semanas após início do RIPE (reduz mortalidade). Se CD4 >50: TARV entre 2-8 semanas após RIPE (quando paciente já tolera). Cuidado: síndrome inflamatória de reconstituição imune (IRIS) — piora paradoxal dos sintomas de TB após início da TARV (febre, linfadenomegalia, piora de lesões). Tratar IRIS com corticoide (prednisona 1 mg/kg/dia por 1-4 sem). Profilaxia com TMP-SMX: todos os pacientes com HIV + TB devem receber TMP-SMX (sulfametoxazol + trimetoprima) 800/160 mg VO 3x/semana (profilaxia de pneumocistose, toxoplasmose, diarreia bacteriana). Manter até CD4 >200 por ≥3 meses e CV suprimida. Prevenção: testar todos os pacientes com TB para HIV. Testar todos os pacientes HIV+ para TB (sintomas + RX tórax + IGRA/PPD). Profilaxia de TB latente com isoniazida (6-9 meses) se PPD≥5mm ou IGRA positivo, após excluir TB ativa.",
                tags = listOf("infectologia", "tb-hiv", "ripe", "tarav", "coinfecção"), citation = "Diretriz MS Brasil 2023 - TB-HIV"),
            LibraryContentItem(id = "infecto_026", title = "Infecção por MRSA — vancomicina", category = "CLINICA_MEDICA",
                summary = "Vancomicina dose de ataque 25-30 mg/kg, manutenção 15-20 mg/kg/dose 12/12h. Trough alvo 15-20 mcg/mL.",
                content = "Infecção por MRSA (S. aureus resistente à meticilina): Vancomicina: glicopeptídeo, inibe parede celular. Dose de ataque: 25-30 mg/kg (dose única, máximo 2.000 mg). Manutenção: 15-20 mg/kg/dose 12/12h IV. Alvo terapêutico (trough): 15-20 mcg/mL (colher 30 min antes da 4ª dose). Ajuste: <10 = aumentar dose; 10-15 = aumentar; 15-20 = manter; >20 = reduzir. Monitorizar função renal (↑ Cr é comum). Efeitos colaterais: nefrotoxicidade (sinergismo com aminoglicosídeos, contraste, AINEs), síndrome do homem vermelho (infusão rápida → liberação de histamina — tratar com difenidramina, infundir em ≥1h). Alternativas: Linezolida 600 mg 12/12h EV/VO (boa penetração no SNC, pulmão; risco de trombocitopenia e inibição MAO). Daptomicina 6-10 mg/kg/dia IV (evitar na pneumonia). Ceftarolina 600 mg 8/8h IV (cefalosporina anti-MRSA). TMP-SMX (sulfametoxazol + trimetoprima) — dose alta 10-20 mg/kg/dia (componente TMP). Tedizolida 200 mg/dia. Duração: bacteremia MRSA: 14 dias. Pneumonia MRSA: 14 dias. Endocardite MRSA: 6 semanas. Osteomielite: 6-12 semanas. Avaliar se necessidade de drenagem de abscesso / remoção de dispositivo. Não esquecer de buscar foco (ecocardiograma, US, TC).",
                tags = listOf("infectologia", "mrsa", "vancomicina", "resistência"), citation = "Diretriz IDSA 2023 - MRSA"),
            LibraryContentItem(id = "infecto_027", title = "Enterobactérias ESBL — tratamento", category = "CLINICA_MEDICA",
                summary = "Carbapenêmico (meropenem 1g 8/8h, imipenem 0,5g 6/6h, ertapenem 1g/dia). Evitar cefalosporinas (resistentes).",
                content = "Enterobactérias produtoras de β-lactamase de espectro estendido (ESBL): Escherichia coli, Klebsiella pneumoniae, Proteus. Mecanismo: hidrolisam cefalosporinas de 3ª geração e aztreonam. Suscetíveis: carbapenêmicos (tratamento de escolha). Tratamento: meropenem 1g 8/8h IV, imipenem 0,5g 6/6h IV, ou ertapenem 1g/dia IV (em infecções menos graves, sem Pseudomonas). Alternativas (se MIC ≤1 ou foco urinário): cefepima (doses altas 2g 8/8h), piperacilina-tazobactam (4,5g 6/6h), temocilina (se disponível), cefoxitina (ITU). Se o isolado for susceptível, TMP-SMX e amicacina podem ser alternativas. Cistite por ESBL: fosfomicina 3g dose única, nitrofurantoína 100 mg 6/6h por 5-7 dias, ou TMP-SMX se sensível. Evitar: cefalosporinas de 3ª geração (ceftriaxona, cefotaxima). A resistência confere falha clínica. Duração: 7-14 dias. Sempre fazer antibiograma e descalonar quando possível. Epidemiologia: a resistência mediada por ESBL está aumentando rapidamente. KPC (Klebsiella pneumoniae carbapenemase): resistência a carbapenêmicos. Tratar com: polimixina B + tigeciclina + ± meropenem (se MIC ≤8) + ± aminoglicosídeo. Ceftazidima-avibactam é tratamento dirigido para KPC. Alguns hospitais brasileiros têm surtos de KPC.",
                tags = listOf("infectologia", "esbl", "carbapenêmico", "meropenem", "resistência"), citation = "Diretriz MS Brasil/ANVISA 2023 - Resistência Antimicrobiana"),
            LibraryContentItem(id = "infecto_028", title = "Acinetobacter baumannii — tratamento", category = "CLINICA_MEDICA",
                summary = "Polimixina B (15.000-25.000 UI/kg/dia) + tigeciclina 100 mg ataque, 50 mg 12/12h. Sulbactam 12g/dia é alternativa.",
